import React, { useState, useEffect } from 'react';
import { createRoot } from 'react-dom/client';
import { GoogleGenAI } from "@google/genai";

const App = () => {
  // --- STATE MANAGEMENT ---
  const [unitTitle, setUnitTitle] = useState('MANAGE GUEST EXPERINCE');
  const [level, setLevel] = useState('Level 6');
  const [trainerName, setTrainerName] = useState('PATRICIA J.G');
  const [institutionName, setInstitutionName] = useState('Kenya Technical Trainers College');
  const [numWeeks, setNumWeeks] = useState('3');
  const [numLessons, setNumLessons] = useState('2');
  const [curriculum, setCurriculum] = useState(
    `Unit Description: To manage guest experience, carry out market research, handle guest communication and feedback so as to enhance guest's experience and leave a lasting impression.

Key Elements and Competencies:

1.  **Carry out market research**
    - 1.1 Tools for market research are utilized as per acceptable market research techniques and service delivery targets.
    - 1.2 Market research is conducted as per acceptable market research techniques and workplace policy.
    - 1.3 Collected data and information is analysed and reported based on acceptable research standard and within confidentiality limits.
    - 1.4 Market research report is evaluated and implemented as per SOPs and workplace policy.
    - 1.5 Guest expectations are concretized based on market research findings.

2.  **Conduct Market research**
    - 2.1 Identify and explain acceptable market research techniques and work place policy(SOPs)
    - 2.2 Use research tools to conduct market research on guest experience

3.  **Data Analysis and reporting**
    - 3.1 Define the term: data, information,d ata analysis
    - 3.2 Identify tools for data analysis
    - 3.3 Analyse, interprete and present results on market research

4.  **Implimentation of Market research**
    - 4.1 Come up with appropriate recommendations on how to manage guest experience as per SOPs and workplac e policy.

5.  **Summarize research findings**
    - 5.1 Write a summarized research findings on managing guest expectation`
  );

  const [learningPlan, setLearningPlan] = useState('');
  const [sessionPlans, setSessionPlans] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [generationStep, setGenerationStep] = useState('');
  const [error, setError] = useState('');
  const [warning, setWarning] = useState('');
  const [activeTab, setActiveTab] = useState('learningPlan');
  const [isApiConfigured, setIsApiConfigured] = useState(false);
  const [logoSrc, setLogoSrc] = useState('');

  // --- API KEY CHECK ---
  useEffect(() => {
    const keyIsAvailable = typeof process !== 'undefined' &&
                           typeof process.env !== 'undefined' &&
                           !!process.env.API_KEY &&
                           process.env.API_KEY.trim() !== '';
    setIsApiConfigured(keyIsAvailable);
  }, []);

  const handleLogoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (loadEvent) => {
        setLogoSrc(loadEvent.target?.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  // --- API CALL ---
  const handleGenerate = async (e: React.FormEvent) => {
    e.preventDefault();

    if (!isApiConfigured) {
      setError("Configuration Error: The API_KEY is not available. Please ensure it is correctly configured.");
      return;
    }

    setIsLoading(true);
    setError('');
    setWarning('');
    setLearningPlan('');
    setSessionPlans('');
    setActiveTab('learningPlan');

    const currentDate = new Date().toLocaleDateString('en-GB');
    const totalSessions = parseInt(numWeeks) * parseInt(numLessons);

    const logoBlock = logoSrc 
      ? `<img src="${logoSrc}" alt="Logo" style="max-height: 80px; display: block; margin: 0 auto 10px;" />` 
      : `<h3 style="color: red; font-weight: bold; text-transform: uppercase;">INSTITUTION LOGO/LETTER HEAD</h3>`;

    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    try {
      // --- PHASE 1: GENERATE LEARNING PLAN ---
      setGenerationStep('Step 1: Generating Learning Plan Matrix...');
      const lpSystemInstruction = `You are a TVET CDACC expert. Generate ONLY the Learning Plan HTML table for the provided unit. 
      Use this structure:
      <div class="learning-plan-output">
        <div style="text-align: center; margin-bottom: 20px;">
          ${logoBlock}
          <h3 style="margin: 0;">${institutionName}</h3>
          <h2 style="margin: 10px 0;">LEARNING PLAN TEMPLATE</h2>
        </div>
        <table class="meta-table">...</table>
        <div class="meta-details">...</div>
        <table class="main-plan-table">
          <thead>...</thead>
          <tbody><!-- Generate rows for ${totalSessions} sessions --></tbody>
        </table>
      </div>
      Distribute the curriculum competencies across exactly ${totalSessions} sessions. 
      Ensure 'Learning Checks' include Knowledge, Skills, and Attitudes subheadings.`;

      const lpResponse = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Generate Learning Plan for: Unit: ${unitTitle}, Level: ${level}, Trainer: ${trainerName}, Institution: ${institutionName}, Sessions: ${totalSessions}. Curriculum: ${curriculum}`,
        config: { systemInstruction: lpSystemInstruction }
      });

      const generatedLP = lpResponse.text || '';
      setLearningPlan(generatedLP);

      // --- PHASE 2: GENERATE SESSION PLANS IN BATCHES ---
      const batchSize = 2; // Generate 2 sessions at a time for maximum detail
      const numBatches = Math.ceil(totalSessions / batchSize);
      let allSessionPlans = '';

      for (let i = 0; i < numBatches; i++) {
        const startSession = i * batchSize + 1;
        const endSession = Math.min((i + 1) * batchSize, totalSessions);
        setGenerationStep(`Step ${i + 2} of ${numBatches + 1}: Generating Session Plans ${startSession}-${endSession}...`);

        const spSystemInstruction = `You are a TVET CDACC expert. Generate highly detailed Session Plan HTML for sessions ${startSession} through ${endSession} based on the previously created Learning Plan. 
        Each session must follow this structure exactly:
        <div class="session-plan-container">
          <div style="text-align: center; margin-bottom: 20px;">${logoBlock}<p><strong>${institutionName}</strong></p></div>
          <table class="session-plan-meta">...</table>
          <table class="session-plan-body">
            <tr><td><strong>Bridge-in (5 min)</strong>...</td></tr>
            <tr><td><strong>Learning Outcome:</strong><br/>By the end of the session, the trainee will be able to;...</td></tr>
            <tr><td><strong>Pre-assessment (10 min)</strong>...</td></tr>
            <tr><td><strong>Participatory Learning (80 min)</strong>...</td></tr>
            <tr><td><strong>Post-Assessment (15 min)</strong>...</td></tr>
            <tr><td><strong>Summary/Closure (10 min)</strong>...</td></tr>
          </table>
        </div>
        TOTAL TIME MUST BE 120 MINUTES PER SESSION. DO NOT TRUNCATE.`;

        const spResponse = await ai.models.generateContent({
          model: 'gemini-3-flash-preview',
          contents: `Using this Learning Plan context: ${generatedLP.substring(0, 3000)}, generate detailed Session Plans for Session ${startSession} to ${endSession}.`,
          config: { systemInstruction: spSystemInstruction }
        });

        allSessionPlans += spResponse.text || '';
        setSessionPlans(prev => prev + (spResponse.text || ''));
      }

    } catch (err: any) {
      console.error(err);
      setError(err.message || 'An error occurred during generation.');
    } finally {
      setIsLoading(false);
      setGenerationStep('');
    }
  };

  const handleDownload = (html: string, titleSuffix: string) => {
    if (!html) return;
    const fileName = `${unitTitle.replace(/ /g, '_')}_${titleSuffix}.docx`;
    const orientation = titleSuffix === 'Learning_Plan' ? 'landscape' : 'portrait';

    const sourceHTML = `
      <!DOCTYPE html>
      <html xmlns:o='urn:schemas-microsoft-com:office:office' xmlns:w='urn:schemas-microsoft-com:office:word' xmlns='http://www.w3.org/TR/REC-html40'>
      <head>
        <meta charset='utf-8'>
        <style>
          @page { size: A4 ${orientation}; margin: 1.5cm; }
          body { font-family: 'Times New Roman', serif; font-size: 10pt; }
          table { border-collapse: collapse; width: 100%; margin-bottom: 1rem; }
          th, td { border: 1px solid black; padding: 4px; vertical-align: top; }
          .session-plan-container { page-break-after: always; }
        </style>
      </head>
      <body>${html}</body>
      </html>`;

    const blob = new Blob([sourceHTML], { type: 'application/vnd.ms-word' });
    const link = document.createElement('a');
    link.href = URL.createObjectURL(blob);
    link.download = fileName;
    link.click();
  };

  return (
    <>
      <style>{STYLES}</style>
      <div className="app-container">
        <aside className="sidebar">
          <header className="sidebar-header">
            <h1>TVET EduPlanner</h1>
            <p>High-Precision Lesson Planning</p>
            <p className="creator-credit">Enhanced for Complete Outputs</p>
          </header>
          <form onSubmit={handleGenerate} className="input-form">
            <div className="form-group">
              <label>Unit Title</label>
              <input type="text" value={unitTitle} onChange={(e) => setUnitTitle(e.target.value)} required disabled={isLoading} />
            </div>
            <div className="form-group">
              <label>Level</label>
              <input type="text" value={level} onChange={(e) => setLevel(e.target.value)} required disabled={isLoading} />
            </div>
            <div className="form-group">
              <label>Trainer Name</label>
              <input type="text" value={trainerName} onChange={(e) => setTrainerName(e.target.value)} required disabled={isLoading} />
            </div>
            <div className="form-group">
              <label>Institution Name</label>
              <input type="text" value={institutionName} onChange={(e) => setInstitutionName(e.target.value)} required disabled={isLoading} />
            </div>

            <div className="form-group">
              <label>Institution Logo</label>
              <div className="logo-uploader">
                <input type="file" id="logoUpload" accept="image/*" onChange={handleLogoUpload} style={{ display: 'none' }} />
                <label htmlFor="logoUpload" className="logo-upload-label">
                  {logoSrc ? <img src={logoSrc} className="logo-preview" /> : <span>🖼️ Upload Logo</span>}
                </label>
                {logoSrc && <button type="button" className="remove-logo-btn" onClick={() => setLogoSrc('')}>Remove</button>}
              </div>
            </div>

            <div className="form-grid">
              <div className="form-group">
                <label>No. of Weeks</label>
                <input type="number" value={numWeeks} onChange={(e) => setNumWeeks(e.target.value)} required min="1" disabled={isLoading} />
              </div>
              <div className="form-group">
                <label>Lessons/Week</label>
                <input type="number" value={numLessons} onChange={(e) => setNumLessons(e.target.value)} required min="1" disabled={isLoading} />
              </div>
            </div>
            <div className="form-group">
              <label>Unit Curriculum</label>
              <textarea value={curriculum} onChange={(e) => setCurriculum(e.target.value)} rows={8} required disabled={isLoading}></textarea>
            </div>

            <button type="submit" className="generate-btn" disabled={isLoading || !isApiConfigured}>
              {isLoading ? 'Generating...' : 'Generate Complete Plan'}
            </button>
            {!isApiConfigured && <p className="api-notice">⚠️ API Key Required in Environment</p>}
          </form>
        </aside>

        <main className="main-content">
          {isLoading && (
            <div className="loading-spinner">
              <div className="spinner"></div>
              <h3>{generationStep}</h3>
              <p>We are generating your plans in sections to ensure maximum detail and completeness.</p>
            </div>
          )}

          {error && <div className="error-message">{error}</div>}

          {!isLoading && !learningPlan && !error && (
             <div className="placeholder">
                <div className="placeholder-icon">📚</div>
                <h2>Ready to Plan?</h2>
                <p>Fill in the details and we'll generate a complete TVET-standard Learning Plan and Session Plans for you.</p>
             </div>
          )}

          {(learningPlan || sessionPlans) && (
            <div className="results-container">
              <div className="tabs-bar">
                <div className="tabs">
                  <button className={`tab-btn ${activeTab === 'learningPlan' ? 'active' : ''}`} onClick={() => setActiveTab('learningPlan')}>
                    Learning Plan
                  </button>
                  <button className={`tab-btn ${activeTab === 'sessionPlans' ? 'active' : ''}`} onClick={() => setActiveTab('sessionPlans')} disabled={!sessionPlans}>
                    Session Plans {isLoading && ' (Generating...)'}
                  </button>
                </div>
                <div className="actions">
                  {activeTab === 'learningPlan' && learningPlan && (
                    <button onClick={() => handleDownload(learningPlan, 'Learning_Plan')} className="download-btn-top">
                      Download LP (.docx)
                    </button>
                  )}
                  {activeTab === 'sessionPlans' && sessionPlans && (
                    <button onClick={() => handleDownload(sessionPlans, 'Session_Plans')} className="download-btn-top">
                      Download SPs (.docx)
                    </button>
                  )}
                </div>
              </div>

              <div className="tab-content">
                {activeTab === 'learningPlan' && <div className="html-output" dangerouslySetInnerHTML={{ __html: learningPlan }} />}
                {activeTab === 'sessionPlans' && <div className="html-output" dangerouslySetInnerHTML={{ __html: sessionPlans }} />}
              </div>
            </div>
          )}
        </main>
      </div>
    </>
  );
};

const STYLES = `
  :root {
    --primary-color: #3b82f6;
    --accent-color: #ec4899;
    --bg-color: #f8fafc;
    --surface-color: #ffffff;
    --border-color: #e2e8f0;
    --text-main: #1e293b;
    --text-muted: #64748b;
  }
  * { box-sizing: border-box; margin: 0; padding: 0; }
  body { font-family: 'Inter', sans-serif; background: var(--bg-color); color: var(--text-main); }
  .app-container { display: flex; height: 100vh; overflow: hidden; padding: 1rem; gap: 1rem; }

  .sidebar { width: 420px; background: var(--surface-color); border-radius: 12px; padding: 1.5rem; display: flex; flex-direction: column; border: 1px solid var(--border-color); overflow-y: auto; box-shadow: 0 4px 6px -1px rgb(0 0 0 / 0.1); }
  .sidebar-header h1 { font-size: 1.5rem; background: linear-gradient(to right, var(--primary-color), var(--accent-color)); -webkit-background-clip: text; -webkit-text-fill-color: transparent; margin-bottom: 0.25rem; }
  .sidebar-header p { font-size: 0.875rem; color: var(--text-muted); }
  .creator-credit { font-size: 0.75rem; color: var(--text-muted); margin-top: 0.5rem; font-style: italic; }

  .form-group { margin-bottom: 1rem; }
  .form-group label { display: block; font-size: 0.8rem; font-weight: 600; margin-bottom: 0.35rem; color: var(--text-muted); }
  .form-group input, .form-group textarea { width: 100%; padding: 0.6rem; border: 1px solid var(--border-color); border-radius: 6px; font-size: 0.9rem; }
  .form-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 0.75rem; }

  .logo-uploader { display: flex; align-items: center; gap: 0.75rem; }
  .logo-upload-label { width: 80px; height: 80px; border: 2px dashed var(--border-color); border-radius: 8px; display: flex; align-items: center; justify-content: center; cursor: pointer; overflow: hidden; }
  .logo-preview { width: 100%; height: 100%; object-fit: contain; }
  .remove-logo-btn { padding: 0.25rem 0.5rem; font-size: 0.75rem; background: #fee2e2; color: #ef4444; border: none; border-radius: 4px; cursor: pointer; }

  .generate-btn { padding: 0.8rem; background: linear-gradient(to right, var(--primary-color), var(--accent-color)); color: white; border: none; border-radius: 6px; font-weight: 600; cursor: pointer; margin-top: 1rem; transition: transform 0.1s; }
  .generate-btn:active { transform: scale(0.98); }
  .generate-btn:disabled { opacity: 0.6; cursor: not-allowed; }
  .api-notice { font-size: 0.75rem; color: #ef4444; text-align: center; margin-top: 0.5rem; }

  .main-content { flex: 1; background: var(--surface-color); border-radius: 12px; border: 1px solid var(--border-color); display: flex; flex-direction: column; overflow: hidden; position: relative; }
  .placeholder { flex: 1; display: flex; flex-direction: column; align-items: center; justify-content: center; color: var(--text-muted); text-align: center; padding: 2rem; }
  .placeholder-icon { font-size: 4rem; margin-bottom: 1rem; opacity: 0.5; }

  .loading-spinner { position: absolute; inset: 0; background: rgba(255,255,255,0.9); display: flex; flex-direction: column; align-items: center; justify-content: center; z-index: 50; text-align: center; padding: 2rem; }
  .spinner { width: 40px; height: 40px; border: 4px solid #f3f3f3; border-top: 4px solid var(--primary-color); border-radius: 50%; animation: spin 1s linear infinite; margin-bottom: 1.5rem; }
  @keyframes spin { 0% { transform: rotate(0deg); } 100% { transform: rotate(360deg); } }

  .results-container { flex: 1; display: flex; flex-direction: column; overflow: hidden; }
  .tabs-bar { display: flex; justify-content: space-between; align-items: center; padding: 0 1.5rem; border-bottom: 1px solid var(--border-color); }
  .tab-btn { padding: 1rem 1.5rem; border: none; background: none; font-weight: 600; color: var(--text-muted); cursor: pointer; border-bottom: 2px solid transparent; }
  .tab-btn.active { color: var(--primary-color); border-bottom-color: var(--primary-color); }
  .download-btn-top { padding: 0.5rem 1rem; background: var(--text-main); color: white; border: none; border-radius: 6px; font-size: 0.8rem; cursor: pointer; }

  .tab-content { flex: 1; overflow-y: auto; padding: 1.5rem; }
  .html-output table { border-collapse: collapse; width: 100%; margin-bottom: 2rem; border: 1px solid #ddd; }
  .html-output th, .html-output td { border: 1px solid #ddd; padding: 10px; text-align: left; }
  .html-output th { background: #f8fafc; font-size: 0.85rem; }
  .session-plan-container { margin-bottom: 3rem; border: 1px solid #eee; padding: 1.5rem; border-radius: 8px; }

  @media (max-width: 900px) {
    .app-container { flex-direction: column; height: auto; overflow: visible; }
    .sidebar { width: 100%; height: auto; }
    .main-content { height: 600px; }
  }
`;

const container = document.getElementById('root');
const root = createRoot(container!);
root.render(<App />);

import React, { useState, useEffect } from 'react';
import { createRoot } from 'react-dom/client';
import { GoogleGenAI } from "@google/genai";

const App = () => {
  // --- STATE MANAGEMENT ---
  const [unitTitle, setUnitTitle] = useState('DRAINAGE SYSTEM INSTALLATION I');
  const [unitCode, setUnitCode] = useState('CON/CU/PLM/CR/03/3/MB');
  const [level, setLevel] = useState('Level 3');
  const [trainerName, setTrainerName] = useState('Faith Chess');
  const [trainerNumber, setTrainerNumber] = useState('');
  const [institutionName, setInstitutionName] = useState('ELDAMA RAVINE TVC');
  const [numWeeks, setNumWeeks] = useState('12');
  const [numLessons, setNumLessons] = useState('3');
  const [classGroup, setClassGroup] = useState('F-PLUM/24J');
  const [numTrainees, setNumTrainees] = useState('15');
  const [curriculum, setCurriculum] = useState(
    `Skill or Job Task:
Install environmentally responsive and resource-efficient domestic drainage system, involving installation and maintenance of above and below ground drainage systems.

Benchmark or Criterial to be used:
1. Install above ground drainage system
2. Install below ground drainage system
3. Interpret simple domestic drainage system drawings
4. Maintain drainage systems`
  );

  const [learningPlan, setLearningPlan] = useState('');
  const [sessionPlans, setSessionPlans] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [generationStep, setGenerationStep] = useState('');
  const [error, setError] = useState('');
  const [activeTab, setActiveTab] = useState('learningPlan');
  const [isApiConfigured, setIsApiConfigured] = useState(false);
  const [logoSrc, setLogoSrc] = useState('');

  // --- API KEY CHECK ---
  useEffect(() => {
    const keyIsAvailable = typeof process !== 'undefined' &&
                           typeof process.env !== 'undefined' &&
                           !!process.env.API_KEY &&
                           process.env.API_KEY.trim() !== '';
    setIsApiConfigured(keyIsAvailable);
  }, []);

  const handleLogoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (loadEvent) => {
        setLogoSrc(loadEvent.target?.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  // --- API CALL ---
  const handleGenerate = async (e: React.FormEvent) => {
    e.preventDefault();

    if (!isApiConfigured) {
      setError("Configuration Error: The API_KEY is not available. Please ensure it is correctly configured.");
      return;
    }

    setIsLoading(true);
    setError('');
    setLearningPlan('');
    setSessionPlans('');
    setActiveTab('learningPlan');

    const currentDate = new Date().toLocaleDateString('en-GB');
    const totalSessions = parseInt(numWeeks) * parseInt(numLessons);
    const totalHours = totalSessions * 2;

    const logoBlock = logoSrc 
      ? `<img src="${logoSrc}" alt="Logo" style="max-height: 80px; display: block; margin: 0 auto 10px;" />` 
      : `<div style="text-align:center; padding: 10px; border: 1px dashed #ccc; margin-bottom: 10px;">[INSTITUTION LOGO]</div>`;

    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    try {
      // --- PHASE 1: GENERATE LEARNING PLAN MATRIX ---
      setGenerationStep('Step 1: Generating Learning Plan Template...');
      const lpSystemInstruction = `You are a TVET CDACC expert. Generate a Learning Plan HTML table that EXACTLY matches the provided template structure.

      Structure requirements:
      1. Center the Institution Name: ${institutionName}
      2. Title: LEARNING PLAN TEMPLATE (All caps, centered)
      3. A metadata table with fields:
         - Row 1: Unit of Competency: ${unitTitle} | Unit Code: ${unitCode}
         - Row 2: Name of Trainer: ${trainerName} | TRAINER Number: ${trainerNumber}
         - Row 3: Institution: ${institutionName} | Level: ${level}
         - Row 4: Date of Preparation: ${currentDate} | Date of Revision: [Blank]
         - Row 5: Number of Trainees: ${numTrainees} | Class: ${classGroup}
         - Row 6: TOTAL UNIT HOURS: ${totalHours} HOURS | NUMBER OF SESSIONS: ${totalSessions} OF 2HRS
      4. A section for 'Skill or Job Task' and 'Benchmark or Criterial to be used' based on user input.
      5. The main Learning Plan table with these exact columns:
         - Week
         - Session No.
         - Session Title (Obtained from the PCs)
         - Session Learning Outcome (Based on the content to be covered in the session)
         - Trainer Activities
         - Trainee Activities
         - Resources & Refs
         - Learning Checks/Assessments
         - Reflections & Date

      Generate exactly ${totalSessions} session rows. Use professional TVET language for activities.`;

      const lpResponse = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Generate the full Learning Plan template for: Unit: ${unitTitle}, Code: ${unitCode}, Trainer: ${trainerName}, Sessions: ${totalSessions}. Curriculum Details: ${curriculum}`,
        config: { systemInstruction: lpSystemInstruction }
      });

      const generatedLP = lpResponse.text || '';
      setLearningPlan(generatedLP);

      // --- PHASE 2: GENERATE SESSION PLANS IN BATCHES ---
      const batchSize = 3; 
      const numBatches = Math.ceil(totalSessions / batchSize);

      for (let i = 0; i < numBatches; i++) {
        const startSession = i * batchSize + 1;
        const endSession = Math.min((i + 1) * batchSize, totalSessions);
        setGenerationStep(`Step ${i + 2} of ${numBatches + 1}: Generating Session Plans ${startSession}-${endSession}...`);

        const spSystemInstruction = `You are a TVET CDACC expert. Generate detailed Session Plan HTML for sessions ${startSession} to ${endSession}.
        Each session plan must be on a separate page (use page-break-after: always).
        Structure for each Session Plan:
        - Institution Header & Logo
        - Metadata table (Unit, Code, Trainer, Session No, Date, Time: 2 Hours)
        - Body Table with segments:
          * Bridge-in (5 min)
          * Learning Outcome (Clearly stated)
          * Pre-assessment (10 min)
          * Participatory Learning (80 min) - Divide into Trainer and Trainee activities
          * Post-Assessment (15 min)
          * Summary/Closure (10 min)
        TOTAL TIME MUST BE 120 MINUTES.`;

        const spResponse = await ai.models.generateContent({
          model: 'gemini-3-flash-preview',
          contents: `Based on the following Learning Plan: ${generatedLP.substring(0, 4000)}, generate full Session Plans for Session ${startSession} through ${endSession}.`,
          config: { systemInstruction: spSystemInstruction }
        });

        setSessionPlans(prev => prev + (spResponse.text || ''));
      }

    } catch (err: any) {
      console.error(err);
      setError(err.message || 'An error occurred during generation.');
    } finally {
      setIsLoading(false);
      setGenerationStep('');
    }
  };

