import React, { useState, useEffect } from 'react';
import { createRoot } from 'react-dom/client';
import { GoogleGenAI } from "@google/genai";

const App = () => {
  // --- STATE MANAGEMENT ---
  const [unitTitle, setUnitTitle] = useState('DRAINAGE SYSTEM INSTALLATION I');
  const [unitCode, setUnitCode] = useState('CON/CU/PLM/CR/03/3/MB');
  const [level, setLevel] = useState('Level 3');
  const [trainerName, setTrainerName] = useState('Faith Chess');
  const [trainerNumber, setTrainerNumber] = useState('');
  const [institutionName, setInstitutionName] = useState('ELDAMA RAVINE TVC');
  const [numWeeks, setNumWeeks] = useState('12');
  const [numLessons, setNumLessons] = useState('3');
  const [classGroup, setClassGroup] = useState('F-PLUM/24J');
  const [numTrainees, setNumTrainees] = useState('15');
  const [curriculum, setCurriculum] = useState(
    `Skill or Job Task:
Install environmentally responsive and resource-efficient domestic drainage system, involving installation and maintenance of above and below ground drainage systems.

Benchmark or Criterial to be used:
1. Install above ground drainage system
2. Install below ground drainage system
3. Interpret simple domestic drainage system drawings
4. Maintain drainage systems`
  );

  const [learningPlan, setLearningPlan] = useState('');
  const [sessionPlans, setSessionPlans] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [generationStep, setGenerationStep] = useState('');
  const [error, setError] = useState('');
  const [activeTab, setActiveTab] = useState('learningPlan');
  const [isApiConfigured, setIsApiConfigured] = useState(false);
  const [logoSrc, setLogoSrc] = useState('');

  // --- API KEY CHECK ---
  useEffect(() => {
    const keyIsAvailable = typeof process !== 'undefined' &&
                           typeof process.env !== 'undefined' &&
                           !!process.env.API_KEY &&
                           process.env.API_KEY.trim() !== '';
    setIsApiConfigured(keyIsAvailable);
  }, []);

  const handleLogoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (loadEvent) => {
        setLogoSrc(loadEvent.target?.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  // --- API CALL ---
  const handleGenerate = async (e: React.FormEvent) => {
    e.preventDefault();

    if (!isApiConfigured) {
      setError("Configuration Error: The API_KEY is not available. Please ensure it is correctly configured.");
      return;
    }

    setIsLoading(true);
    setError('');
    setLearningPlan('');
    setSessionPlans('');
    setActiveTab('learningPlan');

    const currentDate = new Date().toLocaleDateString('en-GB');
    const totalSessions = parseInt(numWeeks) * parseInt(numLessons);
    const totalHours = totalSessions * 2;

    const logoBlock = logoSrc 
      ? `<img src="${logoSrc}" alt="Logo" style="max-height: 80px; display: block; margin: 0 auto 10px;" />` 
      : `<div style="text-align:center; padding: 5px; border: 1px dashed #ccc; margin-bottom: 10px; font-weight: bold;">[INSTITUTION LOGO]</div>`;

    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    try {
      // --- PHASE 1: GENERATE LEARNING PLAN MATRIX ---
      setGenerationStep('Step 1: Generating A4 Learning Plan Matrix...');
      const lpSystemInstruction = `You are a TVET CDACC expert. Generate a Learning Plan HTML that is perfectly formatted for A4 LANDSCAPE printing.

      CRITICAL FORMATTING RULES:
      1. Top Header: ${institutionName} (Centered, Bold, H2)
      2. Title: LEARNING PLAN TEMPLATE (Centered, Bold, H1, All Caps)
      3. Metadata Table (Full width, border: 1px solid black):
         - Row 1: "Unit of Competency: ${unitTitle}" (left) | "Unit Code: ${unitCode}" (right)
         - Row 2: "Name of Trainer: ${trainerName}" | "TRAINER Number: ${trainerNumber}"
         - Row 3: "Institution: ${institutionName}" | "Level: ${level}"
         - Row 4: "Date of Preparation: ${currentDate}" | "Date of Revision: "
         - Row 5: "Number of Trainees: ${numTrainees}" | "Class: ${classGroup}"
         - Row 6: "TOTAL UNIT HOURS: ${totalHours} HOURS" | "NUMBER OF SESSIONS: ${totalSessions} OF 2HRS"
      4. Skills & Benchmarks Section:
         - "Skill or Job Task:" followed by the text.
         - "Benchmark or Criterial to be used:" followed by the numbered list.
      5. Main Matrix Table (Exactly 9 columns):
         Columns must have these relative widths for A4:
         - Week (4%)
         - Session No. (4%)
         - Session Title (15%)
         - Session Learning Outcome (15%)
         - Trainer Activities (13%)
         - Trainee Activities (13%)
         - Resources & Refs (13%)
         - Learning Checks/Assessments (15%)
         - Reflections & Date (8%)

      Generate exactly ${totalSessions} rows. Use professional TVET vocabulary. Use style="width: 100%; border-collapse: collapse;" for tables. Use font-family: Arial/sans-serif.`;

      const lpResponse = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Generate the full A4 Learning Plan for: Unit: ${unitTitle}, Code: ${unitCode}, Trainer: ${trainerName}, Sessions: ${totalSessions}. Benchmarks: ${curriculum}`,
        config: { systemInstruction: lpSystemInstruction }
      });

      setLearningPlan(lpResponse.text || '');

      // --- PHASE 2: GENERATE SESSION PLANS IN BATCHES ---
      const batchSize = 3; 
      const numBatches = Math.ceil(totalSessions / batchSize);

      for (let i = 0; i < numBatches; i++) {
        const startSession = i * batchSize + 1;
        const endSession = Math.min((i + 1) * batchSize, totalSessions);
        setGenerationStep(`Step ${i + 2} of ${numBatches + 1}: Generating Session Plans ${startSession}-${endSession}...`);

        const spSystemInstruction = `You are a TVET CDACC expert. Generate detailed Session Plan HTML for sessions ${startSession} to ${endSession}.
        Each plan must be for A4 PORTRAIT orientation.
        Each plan segment:
        - Institution Header
        - Meta Table (Unit, Code, Trainer, Session No, Date, Time: 2 Hours)
        - Body Table (Segmented):
          * Bridge-in (5 min)
          * Learning Outcome
          * Pre-assessment (10 min)
          * Participatory Learning (80 min)
          * Post-Assessment (15 min)
          * Summary/Closure (10 min)
        TOTAL 120 MINUTES.`;

        const spResponse = await ai.models.generateContent({
          model: 'gemini-3-flash-preview',
          contents: `Using this context: ${lpResponse.text?.substring(0, 3000)}, generate detailed Session Plans for ${startSession} to ${endSession}.`,
          config: { systemInstruction: spSystemInstruction }
        });

        setSessionPlans(prev => prev + (spResponse.text || ''));
      }

    } catch (err: any) {
      console.error(err);
      setError(err.message || 'An error occurred during generation.');
    } finally {
      setIsLoading(false);
      setGenerationStep('');
    }
  };

  const handleDownload = (html: string, titleSuffix: string) => {
    if (!html) return;
    const fileName = `${unitTitle.replace(/ /g, '_')}_${titleSuffix}.docx`;
    const orientation = titleSuffix === 'Learning_Plan' ? 'landscape' : 'portrait';

    const sourceHTML = `
      <html xmlns:o='urn:schemas-microsoft-com:office:office' xmlns:w='urn:schemas-microsoft-com:office:word' xmlns='http://www.w3.org/TR/REC-html40'>
      <head>
        <meta charset='utf-8'>
        <style>
          @page { size: A4 ${orientation}; margin: 0.5in; }
          body { font-family: 'Arial', sans-serif; font-size: 8.5pt; color: #000; }
          table { width: 100%; border-collapse: collapse; margin-bottom: 12pt; border: 1px solid black; }
          th, td { border: 1px solid black; padding: 4pt; vertical-align: top; }
          th { background-color: #f2f2f2; font-weight: bold; text-align: center; font-size: 8.5pt; }
          h1, h2, h3 { text-align: center; margin: 4pt 0; text-transform: uppercase; }
          h1 { font-size: 14pt; }
          h2 { font-size: 12pt; }
          .page-break { page-break-after: always; }
        </style>
      </head>
      <body>${html}</body>
      </html>`;

    const blob = new Blob([sourceHTML], { type: 'application/vnd.ms-word' });
    const link = document.createElement('a');
    link.href = URL.createObjectURL(blob);
    link.download = fileName;
    link.click();
  };

  return (
    <>
      <style>{STYLES}</style>
      <div className="app-container">
        <aside className="sidebar">
          <header className="sidebar-header">
            <h1>TVET EduPlanner</h1>
            <p>Professional CDACC A4 Template</p>
          </header>
          <form onSubmit={handleGenerate} className="input-form">
            <div className="form-group">
              <label>Unit of Competency</label>
              <input type="text" value={unitTitle} onChange={(e) => setUnitTitle(e.target.value)} required disabled={isLoading} />
            </div>
            <div className="form-grid">
              <div className="form-group">
                <label>Unit Code</label>
                <input type="text" value={unitCode} onChange={(e) => setUnitCode(e.target.value)} required disabled={isLoading} />
              </div>
              <div className="form-group">
                <label>Level</label>
                <input type="text" value={level} onChange={(e) => setLevel(e.target.value)} required disabled={isLoading} />
              </div>
            </div>
            <div className="form-group">
              <label>Trainer Name</label>
              <input type="text" value={trainerName} onChange={(e) => setTrainerName(e.target.value)} required disabled={isLoading} />
            </div>
            <div className="form-group">
              <label>Institution Name</label>
              <input type="text" value={institutionName} onChange={(e) => setInstitutionName(e.target.value)} required disabled={isLoading} />
            </div>

            <div className="form-group">
              <label>Institution Logo</label>
              <div className="logo-uploader">
                <input type="file" id="logoUpload" accept="image/*" onChange={handleLogoUpload} style={{ display: 'none' }} />
                <label htmlFor="logoUpload" className="logo-upload-label">
                  {logoSrc ? <img src={logoSrc} className="logo-preview" /> : <span>🖼️ Upload</span>}
                </label>
                {logoSrc && <button type="button" className="remove-logo-btn" onClick={() => setLogoSrc('')}>Remove</button>}
              </div>
            </div>

            <div className="form-grid">
              <div className="form-group">
                <label>Weeks</label>
                <input type="number" value={numWeeks} onChange={(e) => setNumWeeks(e.target.value)} required min="1" disabled={isLoading} />
              </div>
              <div className="form-group">
                <label>Sessions/Week</label>
                <input type="number" value={numLessons} onChange={(e) => setNumLessons(e.target.value)} required min="1" disabled={isLoading} />
              </div>
            </div>

            <div className="form-group">
              <label>Class / Group</label>
              <input type="text" value={classGroup} onChange={(e) => setClassGroup(e.target.value)} disabled={isLoading} />
            </div>

            <div className="form-group">
              <label>Curriculum Benchmarks</label>
              <textarea value={curriculum} onChange={(e) => setCurriculum(e.target.value)} rows={6} required disabled={isLoading}></textarea>
            </div>

            <button type="submit" className="generate-btn" disabled={isLoading || !isApiConfigured}>
              {isLoading ? 'Generating A4 Pages...' : 'Generate A4 TVET Plan'}
            </button>
            {!isApiConfigured && <p className="api-notice">⚠️ API Key Required</p>}
          </form>
        </aside>

        <main className="main-content">
          {isLoading && (
            <div className="loading-spinner">
              <div className="spinner"></div>
              <h3>{generationStep}</h3>
              <p>Crafting high-quality A4 formatted documents...</p>
            </div>
          )}

          {error && <div className="error-message">{error}</div>}

          {!isLoading && !learningPlan && !error && (
             <div className="placeholder">
                <div className="placeholder-icon">📐</div>
                <h2>A4 Precision Planning</h2>
                <p>Documents are optimized for standard A4 landscape and portrait printing.</p>
             </div>
          )}

          {(learningPlan || sessionPlans) && (
            <div className="results-container">
              <div className="tabs-bar">
                <div className="tabs">
                  <button className={`tab-btn ${activeTab === 'learningPlan' ? 'active' : ''}`} onClick={() => setActiveTab('learningPlan')}>
                    Learning Plan (A4 Landscape)
                  </button>
                  <button className={`tab-btn ${activeTab === 'sessionPlans' ? 'active' : ''}`} onClick={() => setActiveTab('sessionPlans')} disabled={!sessionPlans}>
                    Session Plans (A4 Portrait)
                  </button>
                </div>
                <div className="actions">
                  <button onClick={() => handleDownload(activeTab === 'learningPlan' ? learningPlan : sessionPlans, activeTab === 'learningPlan' ? 'Learning_Plan' : 'Session_Plans')} className="download-btn-top">
                    Download as Docx
                  </button>
                </div>
              </div>

              <div className="tab-content">
                <div className={`a4-preview ${activeTab === 'learningPlan' ? 'landscape' : 'portrait'}`}>
                   <div className="html-output" dangerouslySetInnerHTML={{ __html: activeTab === 'learningPlan' ? learningPlan : sessionPlans }} />
                </div>
              </div>
            </div>
          )}
        </main>
      </div>
    </>
  );
};

