import React, { useState, useEffect } from 'react';
import { createRoot } from 'react-dom/client';
import { GoogleGenAI } from "@google/genai";

const App = () => {
  // --- STATE MANAGEMENT ---
  const [unitTitle, setUnitTitle] = useState('DRAINAGE SYSTEM INSTALLATION I');
  const [unitCode, setUnitCode] = useState('CON/CU/PLM/CR/03/3/MB');
  const [level, setLevel] = useState('Level 3');
  const [trainerName, setTrainerName] = useState('Faith Chess');
  const [trainerNumber, setTrainerNumber] = useState('');
  const [institutionName, setInstitutionName] = useState('ELDAMA RAVINE TVC');
  const [numWeeks, setNumWeeks] = useState('12');
  const [numLessons, setNumLessons] = useState('3');
  const [classGroup, setClassGroup] = useState('F-PLUM/24J');
  const [numTrainees, setNumTrainees] = useState('15');
  const [curriculum, setCurriculum] = useState(
    `Skill or Job Task:
Install environmentally responsive and resource-efficient domestic drainage system, involving installation and maintenance of above and below ground drainage systems.

Benchmark or Criterial to be used:
1. Install above ground drainage system
2. Install below ground drainage system
3. Interpret simple domestic drainage system drawings
4. Maintain drainage systems`
  );

  const [learningPlan, setLearningPlan] = useState('');
  const [sessionPlans, setSessionPlans] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [generationStep, setGenerationStep] = useState('');
  const [error, setError] = useState('');
  const [activeTab, setActiveTab] = useState('learningPlan');
  const [isApiConfigured, setIsApiConfigured] = useState(false);
  const [logoSrc, setLogoSrc] = useState('');

  // --- API KEY CHECK ---
  useEffect(() => {
    const keyIsAvailable = typeof process !== 'undefined' &&
                           typeof process.env !== 'undefined' &&
                           !!process.env.API_KEY &&
                           process.env.API_KEY.trim() !== '';
    setIsApiConfigured(keyIsAvailable);
  }, []);

  const handleLogoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (loadEvent) => {
        setLogoSrc(loadEvent.target?.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  // --- API CALL ---
  const handleGenerate = async (e: React.FormEvent) => {
    e.preventDefault();

    if (!isApiConfigured) {
      setError("Configuration Error: The API_KEY is not available. Please ensure it is correctly configured.");
      return;
    }

    setIsLoading(true);
    setError('');
    setLearningPlan('');
    setSessionPlans('');
    setActiveTab('learningPlan');

    const currentDate = new Date().toLocaleDateString('en-GB');
    const totalSessions = parseInt(numWeeks) * parseInt(numLessons);
    const totalHours = totalSessions * 2;

    const logoBlock = logoSrc 
      ? `<div style="text-align: center;"><img src="${logoSrc}" alt="Logo" style="max-height: 80px; display: inline-block; margin-bottom: 10px;" /></div>` 
      : `<div style="text-align:center; padding: 5px; border: 1px dashed #ccc; margin-bottom: 10px; font-weight: bold;">[INSTITUTION LOGO]</div>`;

    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    try {
      // --- PHASE 1: GENERATE LEARNING PLAN MATRIX ---
      setGenerationStep('Step 1: Generating A4 Landscape Learning Plan Matrix...');
      const lpSystemInstruction = `You are a TVET CDACC expert. Generate a Learning Plan HTML formatted for A4 LANDSCAPE (11.69in x 8.27in).

      CRITICAL CONTENT REQUIREMENTS:
      - Each session row MUST contain AT LEAST 4 distinct, detailed, and numbered bullet points for "Trainer Activities".
      - Each session row MUST contain AT LEAST 4 distinct, detailed, and numbered bullet points for "Trainee Activities".
      - Activities must follow a logical flow: 1. Introduction/Theory, 2. Demonstration/Observation, 3. Guided Practice/Hands-on, 4. Review/Feedback.

      REQUIRED HTML STRUCTURE:
      1. Center the Institution: <h2 style="text-align: center; margin: 0;">${institutionName}</h2>
      2. Title: <h1 style="text-align: center; margin: 10px 0; text-transform: uppercase; font-size: 16pt;">LEARNING PLAN TEMPLATE</h1>
      3. Metadata Table (Full width, border-collapse: collapse):
         - Row 1: Unit of Competency: ${unitTitle} | Unit Code: ${unitCode}
         - Row 2: Name of Trainer: ${trainerName} | TRAINER Number: ${trainerNumber}
         - Row 3: Institution: ${institutionName} | Level: ${level}
         - Row 4: Date of Preparation: ${currentDate} | Date of Revision: 
         - Row 5: Number of Trainees: ${numTrainees} | Class: ${classGroup}
         - Row 6: TOTAL UNIT HOURS: ${totalHours} HOURS | NUMBER OF SESSIONS: ${totalSessions} OF 2HRS
      4. Skills Section: "Skill or Job Task:" (Bold) and "Benchmark or Criterial to be used:" (Bold) followed by lists.
      5. Main Matrix Table: Exactly 9 columns. Use style="width: 100%; border-collapse: collapse; border: 1px solid black; table-layout: fixed;"

      Generate exactly ${totalSessions} session rows. Use professional TVET terminology. Font-size 8.5pt.`;

      const lpResponse = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Generate the full A4 Landscape Learning Plan with rich, detailed activity lists (minimum 4 points each) for: Unit: ${unitTitle}, Code: ${unitCode}, Trainer: ${trainerName}, Sessions: ${totalSessions}. Curriculum: ${curriculum}`,
        config: { systemInstruction: lpSystemInstruction }
      });

      setLearningPlan(lpResponse.text || '');

      // --- PHASE 2: GENERATE SESSION PLANS IN BATCHES ---
      const batchSize = 3; 
      const numBatches = Math.ceil(totalSessions / batchSize);

      for (let i = 0; i < numBatches; i++) {
        const startSession = i * batchSize + 1;
        const endSession = Math.min((i + 1) * batchSize, totalSessions);
        setGenerationStep(`Step ${i + 2} of ${numBatches + 1}: Generating Detailed Session Plans ${startSession}-${endSession}...`);

        const spSystemInstruction = `You are a TVET CDACC expert. Generate detailed Session Plan HTML for A4 PORTRAIT (8.27in x 11.69in).

        CRITICAL CONTENT REQUIREMENTS:
        - The "Participatory Learning (80 min)" section MUST list at least 5 detailed steps for both the Trainer and Trainee.
        - Ensure a balance of theory and practical skills as per the curriculum.

        Each plan MUST start with:
        - ${logoBlock}
        - <p style="text-align:center; font-weight:bold; margin:0;">${institutionName}</p>
        - Detailed metadata table.
        - Body Table with specific timings (Bridge-in 5, Outcomes, Pre-assessment 10, Participatory Learning 80, Post-Assessment 15, Closure 10).
        TOTAL 120 MINUTES per session. Separate plans with <div class="page-break"></div>.`;

        const spResponse = await ai.models.generateContent({
          model: 'gemini-3-flash-preview',
          contents: `Based on the Learning Plan provided: ${lpResponse.text?.substring(0, 3000)}, generate full A4 Portrait Session Plans for Sessions ${startSession} to ${endSession}. Ensure at least 5 activity points in the Participatory Learning section.`,
          config: { systemInstruction: spSystemInstruction }
        });

        setSessionPlans(prev => prev + (spResponse.text || ''));
      }

    } catch (err: any) {
      console.error(err);
      setError(err.message || 'An error occurred during generation.');
    } finally {
      setIsLoading(false);
      setGenerationStep('');
    }
  };

  const handleDownload = (html: string, titleSuffix: string) => {
    if (!html) return;
    const fileName = `${unitTitle.replace(/ /g, '_')}_${titleSuffix}.docx`;
    const isLandscape = titleSuffix === 'Learning_Plan';
    const orientation = isLandscape ? 'landscape' : 'portrait';

    const sourceHTML = `
      <html xmlns:o='urn:schemas-microsoft-com:office:office' xmlns:w='urn:schemas-microsoft-com:office:word' xmlns='http://www.w3.org/TR/REC-html40'>
      <head>
        <meta charset='utf-8'>
        <style>
          @page {
            size: A4 ${orientation};
            margin: 0.5in;
            mso-page-orientation: ${orientation};
          }
          body { font-family: 'Arial', sans-serif; font-size: 8.5pt; color: #000; }
          table { width: 100%; border-collapse: collapse; margin-bottom: 12pt; border: 1px solid black; }
          th, td { border: 1px solid black; padding: 4pt; vertical-align: top; }
          th { background-color: #f2f2f2; font-weight: bold; text-align: center; font-size: 8.5pt; text-transform: uppercase; }
          h1, h2, h3 { text-align: center; margin: 4pt 0; text-transform: uppercase; }
          h1 { font-size: 14pt; }
          h2 { font-size: 12pt; }
          .page-break { page-break-after: always; mso-special-character: page-break; }
          .html-output table td { word-wrap: break-word; overflow: hidden; }
        </style>
      </head>
      <body>${html}</body>
      </html>`;

    const blob = new Blob([sourceHTML], { type: 'application/msword' });
    const link = document.createElement('a');
    link.href = URL.createObjectURL(blob);
    link.download = fileName;
    link.click();
  };

  return (
    <>
      <style>{STYLES}</style>
      <div className="app-container">
        <aside className="sidebar">
          <header className="sidebar-header">
            <h1>TVET EduPlanner</h1>
            <p>CDACC Standardized Matrix</p>
          </header>
          <form onSubmit={handleGenerate} className="input-form">
            <div className="form-group">
              <label>Unit of Competency</label>
              <input type="text" value={unitTitle} onChange={(e) => setUnitTitle(e.target.value)} required disabled={isLoading} />
