            <div className="form-grid">
              <div className="form-group">
                <label>Unit Code</label>
                <input type="text" value={unitCode} onChange={(e) => setUnitCode(e.target.value)} required disabled={isLoading} />
              </div>
              <div className="form-group">
                <label>Level</label>
                <input type="text" value={level} onChange={(e) => setLevel(e.target.value)} required disabled={isLoading} />
              </div>
            </div>
            <div className="form-group">
              <label>Trainer Name</label>
              <input type="text" value={trainerName} onChange={(e) => setTrainerName(e.target.value)} required disabled={isLoading} />
            </div>
            <div className="form-group">
              <label>Institution Name</label>
              <input type="text" value={institutionName} onChange={(e) => setInstitutionName(e.target.value)} required disabled={isLoading} />
            </div>

            <div className="form-group">
              <label>Institution Logo</label>
              <div className="logo-uploader">
                <input type="file" id="logoUpload" accept="image/*" onChange={handleLogoUpload} style={{ display: 'none' }} />
                <label htmlFor="logoUpload" className="logo-upload-label">
                  {logoSrc ? <img src={logoSrc} className="logo-preview" /> : <span>🖼️ Upload</span>}
                </label>
