              </div>
              <div className="form-group">
                <label>Trainer Number</label>
                <input type="text" value={trainerNumber} onChange={(e) => setTrainerNumber(e.target.value)} disabled={isLoading} />
              </div>
            </div>

            <div className="form-group">
              <label>Trainer Name</label>
              <input type="text" value={trainerName} onChange={(e) => setTrainerName(e.target.value)} required disabled={isLoading} />
