import React, { useState, useEffect } from 'react';
import { createRoot } from 'react-dom/client';
import { GoogleGenAI } from "@google/genai";

const App = () => {
  // --- STATE MANAGEMENT ---
  const [unitTitle, setUnitTitle] = useState('DRAINAGE SYSTEM INSTALLATION I');
  const [level, setLevel] = useState('Level 3');
  const [trainerName, setTrainerName] = useState('Faith Chess');
  const [trainerNumber, setTrainerNumber] = useState('');
  const [institutionName, setInstitutionName] = useState('ELDAMA RAVINE TVC');
  const [numWeeks, setNumWeeks] = useState('12');
  const [numLessons, setNumLessons] = useState('3');
  const [classGroup, setClassGroup] = useState('F-PLUM/24J');
  const [numTrainees, setNumTrainees] = useState('15');
  const [curriculum, setCurriculum] = useState(
    `Unit Code: CON/CU/PLM/CR/03/3/MB

Skill or Job Task:
Install environmentally responsive and resource-efficient domestic drainage system, involving installation and maintenance of above and below ground drainage systems.

Benchmark or Criterial to be used:
1. Install above ground drainage system
2. Install below ground drainage system
3. Interpret simple domestic drainage system drawings
4. Maintain drainage systems`
  );

  const [learningPlan, setLearningPlan] = useState('');
  const [sessionPlans, setSessionPlans] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [isGeneratingSP, setIsGeneratingSP] = useState(false);
  const [generationStep, setGenerationStep] = useState('');
  const [error, setError] = useState('');
  const [activeTab, setActiveTab] = useState('learningPlan');
  const [isApiConfigured, setIsApiConfigured] = useState(false);
  const [logoSrc, setLogoSrc] = useState('');

  // --- API KEY CHECK ---
  useEffect(() => {
    const keyIsAvailable = typeof process !== 'undefined' &&
                           typeof process.env !== 'undefined' &&
                           !!process.env.API_KEY &&
                           process.env.API_KEY.trim() !== '';
    setIsApiConfigured(keyIsAvailable);
  }, []);

  const handleLogoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (loadEvent) => {
        setLogoSrc(loadEvent.target?.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  // --- STEP 1: GENERATE LEARNING PLAN ---
  const handleGenerateLP = async (e: React.FormEvent) => {
    e.preventDefault();

    if (!isApiConfigured) {
      setError("Configuration Error: The API_KEY is not available.");
      return;
    }

    setIsLoading(true);
    setError('');
    setLearningPlan('');
    setSessionPlans('');
    setActiveTab('learningPlan');

    const currentDate = new Date().toLocaleDateString('en-GB');
    const totalSessions = parseInt(numWeeks) * parseInt(numLessons);
    const totalHours = totalSessions * 2;

    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    try {
      setGenerationStep('Extracting Code & Generating A4 Landscape Learning Plan Matrix...');
      const lpSystemInstruction = `You are a TVET CDACC expert. 

      FIRST: Extract the "Unit Code" from the curriculum benchmarks text provided by the user. 

      SECOND: Generate a Learning Plan HTML formatted for A4 LANDSCAPE (11.69in x 8.27in).

      CRITICAL CONTENT REQUIREMENTS:
      - Each session row MUST contain AT LEAST 4 distinct, detailed, and numbered bullet points for "TRAINER ACTIVITIES".
      - Each session row MUST contain AT LEAST 4 distinct, detailed, and numbered bullet points for "TRAINEE ACTIVITIES".
      - Activities MUST follow a professional flow: 1. Introduction, 2. Explanation/Demo, 3. Guided Practice, 4. Conclusion/Check.

      REQUIRED HTML STRUCTURE:
      1. Center the Institution: <h2 style="text-align: center; margin: 0;">${institutionName}</h2>
      2. Title: <h1 style="text-align: center; margin: 10px 0; text-transform: uppercase; font-size: 16pt;">LEARNING PLAN TEMPLATE</h1>
      3. Metadata Table (Full width):
         Use the extracted Unit Code here.
         - Row 1: Unit of Competency: ${unitTitle} | Unit Code: [Extracted Code]
         - Row 2: Name of Trainer: ${trainerName} | TRAINER Number: ${trainerNumber}
         - Row 3: Institution: ${institutionName} | Level: ${level}
         - Row 4: Date of Preparation: ${currentDate} | Date of Revision: 
         - Row 5: Number of Trainees: ${numTrainees} | Class: ${classGroup}
         - Row 6: TOTAL UNIT HOURS: ${totalHours} HOURS | NUMBER OF SESSIONS: ${totalSessions} OF 2HRS
      4. Skills Section: Include the Skills and Benchmarks provided by the user.
      5. Main Matrix Table: Exactly 9 columns. Use style="width: 100%; border-collapse: collapse; border: 1px solid black; table-layout: fixed;"
         THE COLUMNS MUST BE LABELED EXACTLY:
         1. WEEK
         2. SESSION NO
         3. SESSION TITLE
         4. LEARNING OUTCOMES
         5. TRAINER ACTIVITIES
         6. TRAINEE ACTIVITIES
         7. Resources & Refs
         8. Learning Checks/ Assessments
         9. Reflections & Date

      Generate exactly ${totalSessions} rows. Font-size 8.5pt. Use bold headers for the table.`;

      const lpResponse = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Curriculum and Benchmarks: ${curriculum}. Generate the Learning Plan with 9 columns (WEEK, SESSION NO, SESSION TITLE, LEARNING OUTCOMES, TRAINER ACTIVITIES, TRAINEE ACTIVITIES, Resources & Refs, Learning Checks/ Assessments, Reflections & Date) for: Unit Title: ${unitTitle}, Trainer: ${trainerName}, Sessions: ${totalSessions}.`,
        config: { systemInstruction: lpSystemInstruction }
      });

      setLearningPlan(lpResponse.text || '');

    } catch (err: any) {
      console.error(err);
      setError(err.message || 'An error occurred during Learning Plan generation.');
    } finally {
      setIsLoading(false);
      setGenerationStep('');
    }
  };

  // --- STEP 2: GENERATE SESSION PLANS ---
  const handleGenerateSPs = async () => {
    if (!isApiConfigured || !learningPlan) return;

    setIsGeneratingSP(true);
    setError('');
    setActiveTab('sessionPlans');

    const totalSessions = parseInt(numWeeks) * parseInt(numLessons);
    const logoBlock = logoSrc 
      ? `<div style="text-align: center;"><img src="${logoSrc}" alt="Logo" style="max-height: 80px; display: inline-block; margin-bottom: 10px;" /></div>` 
      : `<div style="text-align:center; padding: 5px; border: 1px dashed #ccc; margin-bottom: 10px; font-weight: bold;">[INSTITUTION LOGO]</div>`;

    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    try {
      const batchSize = 3; 
      const numBatches = Math.ceil(totalSessions / batchSize);

      for (let i = 0; i < numBatches; i++) {
        const startSession = i * batchSize + 1;
        const endSession = Math.min((i + 1) * batchSize, totalSessions);
        setGenerationStep(`Generating Session Plans ${startSession}-${endSession} (Batch ${i+1}/${numBatches})...`);

        const spSystemInstruction = `You are a TVET CDACC expert. Generate detailed Session Plan HTML for A4 PORTRAIT (8.27in x 11.69in).

        CRITICAL CONTENT REQUIREMENTS:
        - The "Participatory Learning (80 min)" section MUST list at least 5 detailed, numbered steps for both the Trainer and Trainee.
        - Ensure activities are highly specific to the session title.

        Each plan MUST start with:
        - ${logoBlock}
        - <p style="text-align:center; font-weight:bold; margin:0;">${institutionName}</p>
        - Detailed metadata table (Use the Unit Title: ${unitTitle} and extracted Code).
        - Body Table with segments: Bridge-in (5), Outcomes, Pre-assessment (10), Participatory Learning (80), Post-Assessment (15), Closure (10).
        TOTAL 120 MINUTES per session. Separate plans with <div class="page-break"></div>.`;

        const spResponse = await ai.models.generateContent({
          model: 'gemini-3-flash-preview',
          contents: `Using this Learning Plan as source: ${learningPlan.substring(0, 5000)}, generate full A4 Portrait Session Plans for Sessions ${startSession} to ${endSession}. Ensure 5+ detailed points in the Participatory Learning section.`,
          config: { systemInstruction: spSystemInstruction }
        });

        setSessionPlans(prev => prev + (spResponse.text || ''));
      }
    } catch (err: any) {
      console.error(err);
      setError(err.message || 'An error occurred during Session Plan generation.');
    } finally {
      setIsGeneratingSP(false);
      setGenerationStep('');
    }
  };

  const handleDownload = (html: string, titleSuffix: string) => {
    if (!html) return;
    const fileName = `${unitTitle.replace(/ /g, '_')}_${titleSuffix}.docx`;
    const isLandscape = titleSuffix === 'Learning_Plan';
    const orientation = isLandscape ? 'landscape' : 'portrait';

    const sourceHTML = `
      <html xmlns:o='urn:schemas-microsoft-com:office:office' xmlns:w='urn:schemas-microsoft-com:office:word' xmlns='http://www.w3.org/TR/REC-html40'>
      <head>
        <meta charset='utf-8'>
        <style>
          @page {
            size: A4 ${orientation};
            margin: 0.5in;
            mso-page-orientation: ${orientation};
          }
          body { font-family: 'Arial', sans-serif; font-size: 8.5pt; color: #000; }
          table { width: 100%; border-collapse: collapse; margin-bottom: 12pt; border: 1px solid black; }
          th, td { border: 1px solid black; padding: 4pt; vertical-align: top; }
          th { background-color: #f2f2f2; font-weight: bold; text-align: center; font-size: 8.5pt; text-transform: uppercase; }
          h1, h2, h3 { text-align: center; margin: 4pt 0; text-transform: uppercase; }
          h1 { font-size: 14pt; }
          h2 { font-size: 12pt; }
          .page-break { page-break-after: always; mso-special-character: page-break; }
          ul, ol { margin: 2px 0 2px 15px; padding: 0; }
          li { margin-bottom: 2px; }
        </style>
      </head>
      <body>${html}</body>
      </html>`;

    const blob = new Blob([sourceHTML], { type: 'application/msword' });
    const link = document.createElement('a');
    link.href = URL.createObjectURL(blob);
    link.download = fileName;
    link.click();
  };

  return (
    <>
      <style>{STYLES}</style>
      <div className="app-container">
        <aside className="sidebar">
          <header className="sidebar-header">
            <h1>TVET EduPlanner</h1>
            <p>Smart CDACC Matrix Generator</p>
          </header>
          <form onSubmit={handleGenerateLP} className="input-form">
            <div className="form-group">
              <label>Unit of Competency</label>
              <input type="text" value={unitTitle} onChange={(e) => setUnitTitle(e.target.value)} required disabled={isLoading || isGeneratingSP} />
            </div>

            <div className="form-grid">
              <div className="form-group">
                <label>Level</label>
                <input type="text" value={level} onChange={(e) => setLevel(e.target.value)} required disabled={isLoading || isGeneratingSP} />
              </div>
              <div className="form-group">
                <label>Trainer Number</label>
                <input type="text" value={trainerNumber} onChange={(e) => setTrainerNumber(e.target.value)} disabled={isLoading || isGeneratingSP} />
              </div>
            </div>

            <div className="form-group">
              <label>Trainer Name</label>
              <input type="text" value={trainerName} onChange={(e) => setTrainerName(e.target.value)} required disabled={isLoading || isGeneratingSP} />
            </div>

            <div className="form-group">
              <label>Institution Name</label>
              <input type="text" value={institutionName} onChange={(e) => setInstitutionName(e.target.value)} required disabled={isLoading || isGeneratingSP} />
            </div>

            <div className="form-group">
              <label>Institution Logo</label>
              <div className="logo-uploader">
                <input type="file" id="logoUpload" accept="image/*" onChange={handleLogoUpload} style={{ display: 'none' }} />
                <label htmlFor="logoUpload" className="logo-upload-label">
                  {logoSrc ? <img src={logoSrc} className="logo-preview" /> : <span>🖼️ Upload</span>}
                </label>
                {logoSrc && <button type="button" className="remove-logo-btn" onClick={() => setLogoSrc('')} disabled={isLoading || isGeneratingSP}>Remove</button>}
              </div>
            </div>

            <div className="form-grid">
              <div className="form-group">
                <label>Weeks</label>
                <input type="number" value={numWeeks} onChange={(e) => setNumWeeks(e.target.value)} required min="1" disabled={isLoading || isGeneratingSP} />
              </div>
              <div className="form-group">
                <label>Sessions/Week</label>
                <input type="number" value={numLessons} onChange={(e) => setNumLessons(e.target.value)} required min="1" disabled={isLoading || isGeneratingSP} />
              </div>
            </div>

            <div className="form-group">
              <label>Class / Group</label>
              <input type="text" value={classGroup} onChange={(e) => setClassGroup(e.target.value)} disabled={isLoading || isGeneratingSP} />
            </div>

            <div className="form-group">
              <label>Curriculum (Include Unit Code here)</label>
              <textarea 
                value={curriculum} 
                onChange={(e) => setCurriculum(e.target.value)} 
                rows={6} 
                required 
                placeholder="Paste the curriculum text, including the Unit Code..."
                disabled={isLoading || isGeneratingSP}
              ></textarea>
            </div>

            <button type="submit" className="generate-btn" disabled={isLoading || isGeneratingSP || !isApiConfigured}>
              {isLoading ? 'Processing Learning Plan...' : '1. Generate Learning Plan Preview'}
            </button>
            {!isApiConfigured && <p className="api-notice">⚠️ API Key Missing</p>}
          </form>

          {learningPlan && !isGeneratingSP && (
             <div className="next-step-promo">
                <p>Learning Plan ready! You can now generate individual Session Plans.</p>
                <button onClick={handleGenerateSPs} className="generate-btn secondary">
                   2. Generate All Session Plans
                </button>
             </div>
          )}
        </aside>

        <main className="main-content">
          {(isLoading || isGeneratingSP) && (
            <div className="loading-spinner">
              <div className="spinner"></div>
              <h3>{generationStep}</h3>
              <p>Ensuring 4+ Trainer/Trainee activities per session...</p>
            </div>
          )}

          {error && <div className="error-message">{error}</div>}

          {!isLoading && !isGeneratingSP && !learningPlan && !error && (
             <div className="placeholder">
                <div className="placeholder-icon">📐</div>
                <h2>A4 Matrix Planner</h2>
                <p><b>Step 1:</b> Generate the Learning Plan Matrix (A4 Landscape)<br/><b>Step 2:</b> Review and Generate Session Plans (A4 Portrait)</p>
                <p className="hint">Make sure the Unit Code is in your curriculum text!</p>
             </div>
          )}

          {(learningPlan || sessionPlans) && (
            <div className="results-container">
              <div className="tabs-bar">
                <div className="tabs">
                  <button className={`tab-btn ${activeTab === 'learningPlan' ? 'active' : ''}`} onClick={() => setActiveTab('learningPlan')}>
                    Learning Plan (Landscape)
                  </button>
                  <button className={`tab-btn ${activeTab === 'sessionPlans' ? 'active' : ''}`} onClick={() => setActiveTab('sessionPlans')} disabled={!sessionPlans && !isGeneratingSP}>
                    Session Plans (Portrait) {isGeneratingSP && '...'}
                  </button>
                </div>
                <div className="actions">
                  <button onClick={() => handleDownload(activeTab === 'learningPlan' ? learningPlan : sessionPlans, activeTab === 'learningPlan' ? 'Learning_Plan' : 'Session_Plans')} className="download-btn-top">
                    Download .docx
                  </button>
                </div>
              </div>

              <div className="tab-content">
                <div className={`a4-preview ${activeTab === 'learningPlan' ? 'landscape' : 'portrait'}`}>
                   <div className="html-output" dangerouslySetInnerHTML={{ __html: activeTab === 'learningPlan' ? learningPlan : sessionPlans }} />
                   {!sessionPlans && activeTab === 'sessionPlans' && isGeneratingSP && (
                      <div className="generating-inline-overlay">
                         <div className="spinner"></div>
                         <p>Building detailed session plans...</p>
                      </div>
                   )}
                </div>
              </div>
            </div>
          )}
        </main>
      </div>
    </>
  );
};

