import React, { useState, useEffect } from 'react';
import { createRoot } from 'react-dom/client';
import { GoogleGenAI } from "@google/genai";

const App = () => {
  // --- STATE MANAGEMENT ---
  const [unitTitle, setUnitTitle] = useState('DRAINAGE SYSTEM INSTALLATION I');
  const [level, setLevel] = useState('Level 3');
  const [trainerName, setTrainerName] = useState('Faith Chess');
  const [trainerNumber, setTrainerNumber] = useState('');
  const [institutionName, setInstitutionName] = useState('ELDAMA RAVINE TVC');
  const [numWeeks, setNumWeeks] = useState('12');
  const [numLessons, setNumLessons] = useState('3');
  const [classGroup, setClassGroup] = useState('F-PLUM/24J');
  const [numTrainees, setNumTrainees] = useState('15');
  const [curriculum, setCurriculum] = useState(
    `Unit Code: CON/CU/PLM/CR/03/3/MB

Skill or Job Task:
Install environmentally responsive and resource-efficient domestic drainage system, involving installation and maintenance of above and below ground drainage systems.

Benchmark or Criterial to be used:
1. Install above ground drainage system
2. Install below ground drainage system
3. Interpret simple domestic drainage system drawings
4. Maintain drainage systems`
  );

  const [learningPlan, setLearningPlan] = useState('');
  const [sessionPlans, setSessionPlans] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [isGeneratingSP, setIsGeneratingSP] = useState(false);
  const [generationStep, setGenerationStep] = useState('');
  const [error, setError] = useState('');
  const [activeTab, setActiveTab] = useState('learningPlan');
  const [isApiConfigured, setIsApiConfigured] = useState(false);
  const [logoSrc, setLogoSrc] = useState('');

  // --- API KEY CHECK ---
  useEffect(() => {
    const keyIsAvailable = typeof process !== 'undefined' &&
                           typeof process.env !== 'undefined' &&
                           !!process.env.API_KEY &&
                           process.env.API_KEY.trim() !== '';
    setIsApiConfigured(keyIsAvailable);
  }, []);

  const handleLogoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (loadEvent) => {
        setLogoSrc(loadEvent.target?.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  // --- STEP 1: GENERATE LEARNING PLAN ---
  const handleGenerateLP = async (e: React.FormEvent) => {
    e.preventDefault();

    if (!isApiConfigured) {
      setError("Configuration Error: The API_KEY is not available in the environment.");
      return;
    }

    setIsLoading(true);
    setError('');
    setLearningPlan('');
    setSessionPlans('');
    setActiveTab('learningPlan');

    const currentDate = new Date().toLocaleDateString('en-GB');
    const totalSessions = parseInt(numWeeks) * parseInt(numLessons);
    const totalHours = totalSessions * 2;

    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    try {
      setGenerationStep('Generating high-detail Learning Plan Matrix...');
      const lpSystemInstruction = `You are a TVET CDACC expert. 

      FIRST: Extract the "Unit Code" from the curriculum text provided. 

      SECOND: Generate a Learning Plan HTML formatted for A4 LANDSCAPE (11.69in x 8.27in).

      CRITICAL CONTENT REQUIREMENTS - EVERY CELL MUST BE COMPLETELY FILLED:
      - Column Headers must be exactly: WEEK, SESSION NO, SESSION TITLE, LEARNING OUTCOMES, TRAINER ACTIVITIES, TRAINEE ACTIVITIES, Resources & Refs, Learning Checks/ Assessments, Reflections & Date.

      - THE "LEARNING OUTCOMES" MUST follow this exact pattern: "By the end of the session, trainees should be able to [action] [topic]..." 
      - Outcome Example: "By the end of the session, trainees should be able to identify and apply relevant safety measures and use appropriate Personal Protective Equipment (PPE) for above ground drainage installations."

      - THE "Learning Checks/ Assessments" column (Column 8) MUST follow this structure for every single row:
        Knowledge:
        - Oral questioning on definitions.
        Skills:
        - Participation in discussion.
        Attitudes:
        - Observation of engagement.

      - "TRAINER ACTIVITIES" (Column 5) MUST contain AT LEAST 4 distinct, detailed, and numbered bullet points.
      - "TRAINEE ACTIVITIES" (Column 6) MUST contain AT LEAST 4 distinct, detailed, and numbered bullet points.
      - "Resources & Refs" (Column 7) MUST list specific tools, equipment, and reference materials relevant to that session topic.
      - "Reflections & Date" (Column 9) MUST include a placeholder for feedback and a date (e.g., "Practical mastery observed on ___/___/2024").

      REQUIRED HTML STRUCTURE:
      1. Center the Institution: <h2 style="text-align: center; margin: 0;">${institutionName}</h2>
      2. Title: <h1 style="text-align: center; margin: 10px 0; text-transform: uppercase; font-size: 16pt;">LEARNING PLAN TEMPLATE</h1>
      3. Metadata Table (Full width, border: 1.5px solid black):
         - Row 1: Unit of Competency: ${unitTitle} | Unit Code: [Extracted Code]
         - Row 2: Name of Trainer: ${trainerName} | TRAINER Number: ${trainerNumber}
         - Row 3: Institution: ${institutionName} | Level: ${level}
         - Row 4: Date of Preparation: ${currentDate} | Date of Revision: 
         - Row 5: Number of Trainees: ${numTrainees} | Class: ${classGroup}
         - Row 6: TOTAL UNIT HOURS: ${totalHours} HOURS | NUMBER OF SESSIONS: ${totalSessions} OF 2HRS
      4. Skills Section: Explicitly list the extracted Skills and Benchmarks.
      5. Main Matrix Table: Exactly 9 columns. Use style="width: 100%; border-collapse: collapse; border: 1.5px solid black; table-layout: fixed;"

      Generate exactly ${totalSessions} rows. EVERY CELL MUST BE FILLED. NO BLANKS.`;

      const lpResponse = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Curriculum and Benchmarks: ${curriculum}. Generate the 9-column Learning Plan for Unit: ${unitTitle}, Trainer: ${trainerName}, Sessions: ${totalSessions}. Outcomes must start with "By the end of the session...", Column 8 must follow the K/S/A format, and all other columns must be robustly populated.`,
        config: { systemInstruction: lpSystemInstruction }
      });

      if (!lpResponse.text) throw new Error("Empty response from AI.");
      setLearningPlan(lpResponse.text);

    } catch (err: any) {
      console.error(err);
      setError(err.message || 'An error occurred during Learning Plan generation.');
    } finally {
      setIsLoading(false);
      setGenerationStep('');
    }
  };

  // --- STEP 2: GENERATE SESSION PLANS ---
  const handleGenerateSPs = async () => {
    if (!isApiConfigured || !learningPlan) return;

    setIsGeneratingSP(true);
    setError('');
    setActiveTab('sessionPlans');

    const totalSessions = parseInt(numWeeks) * parseInt(numLessons);
    const logoBlock = logoSrc 
      ? `<div style="text-align: center;"><img src="${logoSrc}" alt="Logo" style="max-height: 80px; display: inline-block; margin-bottom: 10px;" /></div>` 
      : `<div style="text-align:center; padding: 5px; border: 1px dashed #ccc; margin-bottom: 10px; font-weight: bold;">[INSTITUTION LOGO]</div>`;

    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    try {
      const batchSize = 3; 
      const numBatches = Math.ceil(totalSessions / batchSize);

      for (let i = 0; i < numBatches; i++) {
        const startSession = i * batchSize + 1;
        const endSession = Math.min((i + 1) * batchSize, totalSessions);
        setGenerationStep(`Generating Session Plans ${startSession}-${endSession} (Batch ${i+1}/${numBatches})...`);

        const spSystemInstruction = `You are a TVET CDACC expert. Generate detailed Session Plan HTML for A4 PORTRAIT (8.27in x 11.69in).

        CRITICAL CONTENT REQUIREMENTS - EVERY SECTION MUST BE FILLED:
        - The "Outcomes" section MUST follow the pattern: "By the end of the session, trainees should be able to [action] [topic]..."
        - The "Participatory Learning (80 min)" section MUST list at least 6 detailed, numbered steps for both the Trainer and Trainee.
        - The "Resources" section MUST be specific (e.g., "Hack saw, PVC cement, Safety goggles").
        - "Post-Assessment" (15 min) MUST include specific questions or tasks.

        Each plan MUST start with:
        - ${logoBlock}
        - <p style="text-align:center; font-weight:bold; margin:0; font-size: 14pt;">${institutionName}</p>
        - <h3 style="text-align:center; text-decoration: underline;">SESSION PLAN</h3>
        - Detailed metadata table (Unit Name, Code, Session No, Date, Time).
        - Body Table with segments: Bridge-in (5 min), Outcomes, Pre-assessment (10 min), Participatory Learning (80 min), Post-Assessment (15 min), Closure (10 min).
        TOTAL 120 MINUTES per session. Separate plans with <div class="page-break"></div>.

        EVERY PART OF THE PLAN MUST BE COMPLETED IN FULL.`;

        const spResponse = await ai.models.generateContent({
          model: 'gemini-3-flash-preview',
          contents: `Using the previously generated Learning Plan matrix: ${learningPlan.substring(0, 5000)}, generate full A4 Portrait Session Plans for Sessions ${startSession} to ${endSession}. Ensure outcomes match the phrase: "By the end of the session, trainees should be able to..." and every cell in every table is filled.`,
          config: { systemInstruction: spSystemInstruction }
        });

        setSessionPlans(prev => prev + (spResponse.text || ''));
      }
    } catch (err: any) {
      console.error(err);
      setError(err.message || 'An error occurred during Session Plan generation.');
    } finally {
      setIsGeneratingSP(false);
      setGenerationStep('');
    }
  };

  const handleDownload = (html: string, titleSuffix: string) => {
    if (!html) return;
    const fileName = `${unitTitle.replace(/ /g, '_')}_${titleSuffix}.docx`;
    const isLandscape = titleSuffix === 'Learning_Plan';
    const orientation = isLandscape ? 'landscape' : 'portrait';

    const sourceHTML = `
      <html xmlns:o='urn:schemas-microsoft-com:office:office' xmlns:w='urn:schemas-microsoft-com:office:word' xmlns='http://www.w3.org/TR/REC-html40'>
      <head>
        <meta charset='utf-8'>
        <style>
          @page {
            size: A4 ${orientation};
            margin: 0.5in;
            mso-page-orientation: ${orientation};
          }
          body { font-family: 'Arial', sans-serif; font-size: 8.5pt; color: #000; }
          table { width: 100%; border-collapse: collapse; margin-bottom: 12pt; border: 1.5px solid black; }
          th, td { border: 1.5px solid black; padding: 4pt; vertical-align: top; }
          th { background-color: #f2f2f2; font-weight: bold; text-align: center; font-size: 8.5pt; text-transform: uppercase; }
          h1, h2, h3 { text-align: center; margin: 4pt 0; text-transform: uppercase; }
          h1 { font-size: 14pt; }
          h2 { font-size: 12pt; }
          .page-break { page-break-after: always; mso-special-character: page-break; }
          ul, ol { margin: 2px 0 2px 15px; padding: 0; }
          li { margin-bottom: 2px; }
        </style>
      </head>
      <body>${html}</body>
      </html>`;

    const blob = new Blob([sourceHTML], { type: 'application/msword' });
    const link = document.createElement('a');
    link.href = URL.createObjectURL(blob);
    link.download = fileName;
    link.click();
  };

  return (
    <>
      <style>{STYLES}</style>
      <div className="app-container">
        <aside className="sidebar">
          <header className="sidebar-header">
            <h1>TVET EduPlanner</h1>
            <p>Smart CDACC Matrix Generator</p>
          </header>
          <form onSubmit={handleGenerateLP} className="input-form">
            <div className="form-group">
              <label>Unit of Competency</label>
              <input type="text" value={unitTitle} onChange={(e) => setUnitTitle(e.target.value)} required disabled={isLoading || isGeneratingSP} />
            </div>

            <div className="form-grid">
              <div className="form-group">
                <label>Level</label>
                <input type="text" value={level} onChange={(e) => setLevel(e.target.value)} required disabled={isLoading || isGeneratingSP} />
              </div>
              <div className="form-group">
                <label>Trainer Number</label>
                <input type="text" value={trainerNumber} onChange={(e) => setTrainerNumber(e.target.value)} disabled={isLoading || isGeneratingSP} />
              </div>
            </div>

            <div className="form-group">
              <label>Trainer Name</label>
              <input type="text" value={trainerName} onChange={(e) => setTrainerName(e.target.value)} required disabled={isLoading || isGeneratingSP} />
            </div>

            <div className="form-group">
              <label>Institution Name</label>
              <input type="text" value={institutionName} onChange={(e) => setInstitutionName(e.target.value)} required disabled={isLoading || isGeneratingSP} />
            </div>

            <div className="form-group">
              <label>Institution Logo</label>
              <div className="logo-uploader">
                <input type="file" id="logoUpload" accept="image/*" onChange={handleLogoUpload} style={{ display: 'none' }} />
                <label htmlFor="logoUpload" className="logo-upload-label">
                  {logoSrc ? <img src={logoSrc} className="logo-preview" /> : <span>🖼️ Upload</span>}
                </label>
                {logoSrc && <button type="button" className="remove-logo-btn" onClick={() => setLogoSrc('')} disabled={isLoading || isGeneratingSP}>Remove</button>}
              </div>
            </div>

            <div className="form-grid">
              <div className="form-group">
                <label>Weeks</label>
                <input type="number" value={numWeeks} onChange={(e) => setNumWeeks(e.target.value)} required min="1" disabled={isLoading || isGeneratingSP} />
              </div>
              <div className="form-group">
                <label>Sessions/Week</label>
                <input type="number" value={numLessons} onChange={(e) => setNumLessons(e.target.value)} required min="1" disabled={isLoading || isGeneratingSP} />
              </div>
            </div>

            <div className="form-group">
              <label>Class / Group</label>
              <input type="text" value={classGroup} onChange={(e) => setClassGroup(e.target.value)} disabled={isLoading || isGeneratingSP} />
            </div>

            <div className="form-group">
              <label>Curriculum Benchmarks (Include Unit Code)</label>
              <textarea 
                value={curriculum} 
                onChange={(e) => setCurriculum(e.target.value)} 
                rows={6} 
                required 
                placeholder="Paste the curriculum text, including the Unit Code..."
                disabled={isLoading || isGeneratingSP}
              ></textarea>
            </div>

            <button type="submit" className="generate-btn" disabled={isLoading || isGeneratingSP || !isApiConfigured}>
              {isLoading ? 'Processing Learning Plan...' : '1. Generate Learning Plan Preview'}
            </button>
            {!isApiConfigured && <p className="api-notice">⚠️ API Key Missing</p>}
          </form>

          {learningPlan && !isGeneratingSP && (
             <div className="next-step-promo">
                <p>Learning Plan Matrix is ready! Review the columns then generate Session Plans.</p>
                <button onClick={handleGenerateSPs} className="generate-btn secondary">
                   2. Generate All Session Plans
                </button>
             </div>
          )}
        </aside>

        <main className="main-content">
          {(isLoading || isGeneratingSP) && (
            <div className="loading-spinner">
              <div className="spinner"></div>
              <h3>{generationStep}</h3>
              <p>Ensuring 100% data completion for all sessions...</p>
            </div>
          )}

          {error && <div className="error-message">{error}</div>}

          {!isLoading && !isGeneratingSP && !learningPlan && !error && (
             <div className="placeholder">
                <div className="placeholder-icon">📐</div>
                <h2>A4 Matrix Planner</h2>
                <p><b>Step 1:</b> Generate the Learning Plan Matrix (A4 Landscape)<br/><b>Step 2:</b> Review and Generate Session Plans (A4 Portrait)</p>
                <p className="hint">The Unit Code will be extracted automatically from your text!</p>
             </div>
          )}

          {(learningPlan || sessionPlans) && (
            <div className="results-container">
              <div className="tabs-bar">
                <div className="tabs">
                  <button className={`tab-btn ${activeTab === 'learningPlan' ? 'active' : ''}`} onClick={() => setActiveTab('learningPlan')}>
                    Learning Plan (Landscape)
                  </button>
                  <button className={`tab-btn ${activeTab === 'sessionPlans' ? 'active' : ''}`} onClick={() => setActiveTab('sessionPlans')} disabled={!sessionPlans && !isGeneratingSP}>
                    Session Plans (Portrait) {isGeneratingSP && '...'}
                  </button>
                </div>
                <div className="actions">
                  <button onClick={() => handleDownload(activeTab === 'learningPlan' ? learningPlan : sessionPlans, activeTab === 'learningPlan' ? 'Learning_Plan' : 'Session_Plans')} className="download-btn-top">
                    Download .docx
                  </button>
                </div>
              </div>

              <div className="tab-content">
                <div className={`a4-preview ${activeTab === 'learningPlan' ? 'landscape' : 'portrait'}`}>
                   <div className="html-output" dangerouslySetInnerHTML={{ __html: activeTab === 'learningPlan' ? learningPlan : sessionPlans }} />
                   {!sessionPlans && activeTab === 'sessionPlans' && isGeneratingSP && (
                      <div className="generating-inline-overlay">
                         <div className="spinner"></div>
                         <p>Building high-detail session plans from the matrix...</p>
                      </div>
                   )}
                </div>
              </div>
            </div>
          )}
        </main>
      </div>
    </>
  );
};

const STYLES = `
  :root {
    --primary-color: #0f172a;
    --accent-color: #2563eb;
    --secondary-color: #10b981;
    --bg-color: #f1f5f9;
    --surface-color: #ffffff;
    --border-color: #cbd5e1;
    --text-main: #1e293b;
    --text-muted: #64748b;
  }
  * { box-sizing: border-box; margin: 0; padding: 0; }
  body { font-family: 'Inter', sans-serif; background: var(--bg-color); color: var(--text-main); line-height: 1.4; }
  .app-container { display: flex; height: 100vh; overflow: hidden; padding: 0.5rem; gap: 0.5rem; }

  .sidebar { width: 350px; background: var(--surface-color); border-radius: 8px; padding: 1rem; display: flex; flex-direction: column; border: 1px solid var(--border-color); overflow-y: auto; box-shadow: 0 1px 2px rgba(0,0,0,0.05); }
  .sidebar-header { margin-bottom: 1rem; border-bottom: 2px solid var(--accent-color); padding-bottom: 0.5rem; }
  .sidebar-header h1 { font-size: 1.1rem; color: var(--primary-color); font-weight: 800; }
  .sidebar-header p { font-size: 0.65rem; color: var(--accent-color); text-transform: uppercase; font-weight: 700; letter-spacing: 0.05em; }

  .form-group { margin-bottom: 0.65rem; }
  .form-group label { display: block; font-size: 0.65rem; font-weight: 700; margin-bottom: 0.2rem; color: var(--text-muted); text-transform: uppercase; }
  .form-group input, .form-group textarea { width: 100%; padding: 0.45rem; border: 1px solid var(--border-color); border-radius: 4px; font-size: 0.75rem; font-family: inherit; }
  .form-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 0.4rem; }

  .logo-uploader { display: flex; align-items: center; gap: 0.4rem; }
  .logo-upload-label { width: 36px; height: 36px; border: 1px dashed var(--border-color); border-radius: 4px; display: flex; align-items: center; justify-content: center; cursor: pointer; background: #fafafa; font-size: 0.5rem; }
  .logo-preview { width: 100%; height: 100%; object-fit: contain; }
  .remove-logo-btn { font-size: 0.6rem; color: #dc2626; border: none; background: none; cursor: pointer; text-decoration: underline; }

  .generate-btn { padding: 0.75rem; background: var(--accent-color); color: white; border: none; border-radius: 4px; font-weight: 700; cursor: pointer; margin-top: 0.5rem; transition: background 0.2s; font-size: 0.8rem; width: 100%; }
  .generate-btn:hover { background: #1d4ed8; }
  .generate-btn.secondary { background: var(--secondary-color); margin-top: 1rem; }
  .generate-btn.secondary:hover { background: #059669; }
  .generate-btn:disabled { background: #94a3b8; cursor: not-allowed; }

  .next-step-promo { margin-top: 1.5rem; padding: 1rem; background: #ecfdf5; border: 1px solid #10b981; border-radius: 6px; text-align: center; }
  .next-step-promo p { font-size: 0.75rem; font-weight: 600; color: #065f46; margin-bottom: 0.5rem; }

  .main-content { flex: 1; background: #64748b; border-radius: 8px; display: flex; flex-direction: column; overflow: hidden; position: relative; }
  .placeholder { flex: 1; display: flex; flex-direction: column; align-items: center; justify-content: center; color: #334155; text-align: center; padding: 2rem; background: #f1f5f9; border-radius: 4px; margin: 4px; }
  .placeholder-icon { font-size: 2.5rem; margin-bottom: 0.5rem; opacity: 0.1; }
  .hint { font-size: 0.75rem; font-weight: 600; color: var(--accent-color); margin-top: 1rem; }

  .loading-spinner { position: absolute; inset: 0; background: rgba(255,255,255,0.95); display: flex; flex-direction: column; align-items: center; justify-content: center; z-index: 50; }
  .spinner { width: 36px; height: 36px; border: 3px solid #e2e8f0; border-top: 3px solid var(--accent-color); border-radius: 50%; animation: spin 1s linear infinite; margin-bottom: 0.75rem; }
  @keyframes spin { 0% { transform: rotate(0deg); } 100% { transform: rotate(360deg); } }

  .results-container { flex: 1; display: flex; flex-direction: column; overflow: hidden; }
  .tabs-bar { display: flex; justify-content: space-between; align-items: center; padding: 0.4rem 0.75rem; background: #ffffff; border-bottom: 1px solid #cbd5e1; }
  .tabs { display: flex; gap: 0.4rem; }
  .tab-btn { padding: 0.4rem 0.6rem; border: none; background: #f1f5f9; font-weight: 700; color: #475569; cursor: pointer; border-radius: 4px; font-size: 0.7rem; }
  .tab-btn.active { color: white; background: var(--accent-color); }
  .download-btn-top { padding: 0.35rem 0.7rem; background: #0f172a; color: white; border: none; border-radius: 4px; font-size: 0.7rem; cursor: pointer; font-weight: 600; }

  .tab-content { flex: 1; overflow: auto; padding: 1.5rem; display: flex; flex-direction: column; align-items: center; position: relative; }
  .a4-preview { background: white; padding: 0.4in; box-shadow: 0 10px 30px -5px rgba(0, 0, 0, 0.4); border: 1.5px solid #000; box-sizing: content-box; position: relative; }
  .a4-preview.landscape { width: 11in; min-height: 8.5in; }
  .a4-preview.portrait { width: 8in; min-height: 11in; }

  .generating-inline-overlay { position: absolute; inset: 0; background: rgba(255,255,255,0.8); display: flex; flex-direction: column; align-items: center; justify-content: center; z-index: 5; }

  .html-output { color: black; font-family: 'Times New Roman', Times, serif; }
  .html-output table { border-collapse: collapse; width: 100%; margin-bottom: 8px; border: 1.5px solid black; }
  .html-output th, .html-output td { border: 1.5px solid black; padding: 3px; text-align: left; font-size: 7.5pt; vertical-align: top; line-height: 1.15; word-wrap: break-word; }
  .html-output th { background: #f8fafc; font-weight: bold; text-align: center; text-transform: uppercase; }
  .html-output h1 { font-size: 12pt; margin: 4px 0; text-align: center; }
  .html-output h2 { font-size: 10pt; margin: 2px 0; text-align: center; }
  .html-output p { font-size: 8pt; margin: 2px 0; }
  .html-output ul, .html-output ol { margin: 1px 0 1px 12px; padding: 0; }
  .html-output li { margin-bottom: 1px; }

  .error-message { background: #fee2e2; color: #b91c1c; padding: 0.75rem; border-radius: 4px; margin: 1rem; text-align: center; font-size: 0.75rem; font-weight: 600; border: 1px solid #f87171; }
  .api-notice { font-size: 0.6rem; color: #dc2626; margin-top: 0.25rem; font-weight: bold; text-align: center; }

  @media (max-width: 1100px) {
    .app-container { flex-direction: column; height: auto; overflow: visible; }
    .sidebar { width: 100%; height: auto; }
    .main-content { height: 800px; }
  }
`;

const container = document.getElementById('root');
const root = createRoot(container!);
root.render(<App />);

import React, { useState, useEffect } from 'react';
import { createRoot } from 'react-dom/client';
import { GoogleGenAI } from "@google/genai";

const App = () => {
  // --- STATE MANAGEMENT ---
  const [unitTitle, setUnitTitle] = useState('DRAINAGE SYSTEM INSTALLATION I');
  const [level, setLevel] = useState('Level 3');
  const [trainerName, setTrainerName] = useState('Faith Chess');
  const [trainerNumber, setTrainerNumber] = useState('');
  const [institutionName, setInstitutionName] = useState('ELDAMA RAVINE TVC');
  const [numWeeks, setNumWeeks] = useState('12');
  const [numLessons, setNumLessons] = useState('3');
  const [classGroup, setClassGroup] = useState('F-PLUM/24J');
  const [numTrainees, setNumTrainees] = useState('15');
  const [curriculum, setCurriculum] = useState(
    `Unit Code: CON/CU/PLM/CR/03/3/MB

Skill or Job Task:
Install environmentally responsive and resource-efficient domestic drainage system, involving installation and maintenance of above and below ground drainage systems.

Benchmark or Criterial to be used:
1. Install above ground drainage system
2. Install below ground drainage system
3. Interpret simple domestic drainage system drawings
4. Maintain drainage systems`
  );

  const [learningPlan, setLearningPlan] = useState('');
  const [sessionPlans, setSessionPlans] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [isGeneratingSP, setIsGeneratingSP] = useState(false);
  const [generationStep, setGenerationStep] = useState('');
  const [error, setError] = useState('');
  const [activeTab, setActiveTab] = useState('learningPlan');
  const [isApiConfigured, setIsApiConfigured] = useState(false);
  const [logoSrc, setLogoSrc] = useState('');

  // --- API KEY CHECK ---
  useEffect(() => {
    const keyIsAvailable = typeof process !== 'undefined' &&
                           typeof process.env !== 'undefined' &&
                           !!process.env.API_KEY &&
                           process.env.API_KEY.trim() !== '';
    setIsApiConfigured(keyIsAvailable);
  }, []);

  const handleLogoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (loadEvent) => {
        setLogoSrc(loadEvent.target?.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const getLogoHtml = () => {
    return logoSrc 
      ? `<div style="text-align: center;"><img src="${logoSrc}" alt="Logo" style="max-height: 80px; display: inline-block; margin-bottom: 5px;" /></div>` 
      : `<div style="text-align:center; padding: 5px; border: 1px dashed #ccc; margin-bottom: 5px; font-weight: bold; font-size: 8pt;">[INSTITUTION LOGO]</div>`;
  };

  // --- STEP 1: GENERATE LEARNING PLAN ---
  const handleGenerateLP = async (e: React.FormEvent) => {
    e.preventDefault();

    if (!isApiConfigured) {
      setError("Configuration Error: The API_KEY is not available in the environment.");
      return;
    }

    setIsLoading(true);
    setError('');
    setLearningPlan('');
    setSessionPlans('');
    setActiveTab('learningPlan');

    const currentDate = new Date().toLocaleDateString('en-GB');
    const totalSessions = parseInt(numWeeks) * parseInt(numLessons);
    const totalHours = totalSessions * 2;
    const logoBlock = getLogoHtml();

    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    try {
      setGenerationStep('Generating high-detail Learning Plan Matrix with Logo...');
      const lpSystemInstruction = `You are a TVET CDACC expert. 

      FIRST: Extract the "Unit Code" from the curriculum text provided. 

      SECOND: Generate a Learning Plan HTML formatted for A4 LANDSCAPE (11.69in x 8.27in).

      CRITICAL LAYOUT REQUIREMENT:
      - Include the following logo block at the very top: ${logoBlock}

      CRITICAL CONTENT REQUIREMENTS - EVERY CELL MUST BE COMPLETELY FILLED:
      - Column Headers must be exactly: WEEK, SESSION NO, SESSION TITLE, LEARNING OUTCOMES, TRAINER ACTIVITIES, TRAINEE ACTIVITIES, Resources & Refs, Learning Checks/ Assessments, Reflections & Date.

      - THE "LEARNING OUTCOMES" MUST follow this exact pattern: "By the end of the session, trainees should be able to [action] [topic]..." 

      - THE "Learning Checks/ Assessments" column (Column 8) MUST follow this structure for every single row:
        Knowledge:
        - Oral questioning on definitions.
        Skills:
        - Participation in discussion.
        Attitudes:
        - Observation of engagement.

      - "TRAINER ACTIVITIES" (Column 5) MUST contain AT LEAST 4 distinct, detailed, and numbered bullet points.
      - "TRAINEE ACTIVITIES" (Column 6) MUST contain AT LEAST 4 distinct, detailed, and numbered bullet points.
      - "Resources & Refs" (Column 7) MUST list specific tools, equipment, and reference materials.
      - "Reflections & Date" (Column 9) MUST include a placeholder like "Practical mastery observed on ___/___/2024".

      REQUIRED HTML STRUCTURE:
      1. Logo: ${logoBlock}
      2. Center the Institution: <h2 style="text-align: center; margin: 0;">${institutionName}</h2>
      3. Title: <h1 style="text-align: center; margin: 5px 0; text-transform: uppercase; font-size: 14pt;">LEARNING PLAN TEMPLATE</h1>
      4. Metadata Table (Full width, border: 1.5px solid black):
         - Row 1: Unit of Competency: ${unitTitle} | Unit Code: [Extracted Code]
         - Row 2: Name of Trainer: ${trainerName} | TRAINER Number: ${trainerNumber}
         - Row 3: Institution: ${institutionName} | Level: ${level}
         - Row 4: Date of Preparation: ${currentDate} | Date of Revision: 
         - Row 5: Number of Trainees: ${numTrainees} | Class: ${classGroup}
         - Row 6: TOTAL UNIT HOURS: ${totalHours} HOURS | NUMBER OF SESSIONS: ${totalSessions} OF 2HRS
      5. Main Matrix Table: Exactly 9 columns. EVERY CELL MUST BE FILLED.

      Generate exactly ${totalSessions} rows.`;

      const lpResponse = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Curriculum and Benchmarks: ${curriculum}. Generate the 9-column Learning Plan for Unit: ${unitTitle}, Trainer: ${trainerName}, Sessions: ${totalSessions}. Outcomes must start with "By the end of the session...", Column 8 must follow the K/S/A format, and ALL columns must be robustly populated.`,
        config: { systemInstruction: lpSystemInstruction }
      });

      if (!lpResponse.text) throw new Error("Empty response from AI.");
      setLearningPlan(lpResponse.text);

    } catch (err: any) {
      console.error(err);
      setError(err.message || 'An error occurred during Learning Plan generation.');
    } finally {
      setIsLoading(false);
      setGenerationStep('');
    }
  };

  // --- STEP 2: GENERATE SESSION PLANS ---
  const handleGenerateSPs = async () => {
    if (!isApiConfigured || !learningPlan) return;

    setIsGeneratingSP(true);
    setError('');
    setActiveTab('sessionPlans');

    const totalSessions = parseInt(numWeeks) * parseInt(numLessons);
    const logoBlock = getLogoHtml();

    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    try {
      const batchSize = 3; 
      const numBatches = Math.ceil(totalSessions / batchSize);

      for (let i = 0; i < numBatches; i++) {
        const startSession = i * batchSize + 1;
        const endSession = Math.min((i + 1) * batchSize, totalSessions);
        setGenerationStep(`Generating Session Plans ${startSession}-${endSession} (Batch ${i+1}/${numBatches})...`);

        const spSystemInstruction = `You are a TVET CDACC expert. Generate detailed Session Plan HTML for A4 PORTRAIT (8.27in x 11.69in).

        CRITICAL LAYOUT REQUIREMENT:
        - Include the following logo block at the very top of every session plan: ${logoBlock}

        CRITICAL CONTENT REQUIREMENTS - EVERY SECTION MUST BE FILLED:
        - The "Outcomes" section MUST follow the pattern: "By the end of the session, trainees should be able to [action] [topic]..."
        - The "Participatory Learning (80 min)" section MUST list at least 6 detailed, numbered steps for both the Trainer and Trainee.
        - Every cell in every table must be filled with specific information.

        Each plan MUST start with:
        - ${logoBlock}
        - <p style="text-align:center; font-weight:bold; margin:0; font-size: 13pt;">${institutionName}</p>
        - <h3 style="text-align:center; text-decoration: underline; margin-bottom: 10px;">SESSION PLAN</h3>
        - Detailed metadata table (Unit Name, Code, Session No, Date, Time).
        - Body Table with segments: Bridge-in (5 min), Outcomes, Pre-assessment (10 min), Participatory Learning (80 min), Post-Assessment (15 min), Closure (10 min).
        TOTAL 120 MINUTES per session. Separate plans with <div class="page-break"></div>.`;

        const spResponse = await ai.models.generateContent({
          model: 'gemini-3-flash-preview',
          contents: `Using the previously generated Learning Plan matrix: ${learningPlan.substring(0, 5000)}, generate full A4 Portrait Session Plans for Sessions ${startSession} to ${endSession}. Ensure logo is included and outcomes match "By the end of the session, trainees should be able to..."`,
          config: { systemInstruction: spSystemInstruction }
        });

        setSessionPlans(prev => prev + (spResponse.text || ''));
      }
    } catch (err: any) {
      console.error(err);
      setError(err.message || 'An error occurred during Session Plan generation.');
    } finally {
      setIsGeneratingSP(false);
      setGenerationStep('');
    }
  };

  const handleDownload = (html: string, titleSuffix: string) => {
    if (!html) return;
    const fileName = `${unitTitle.replace(/ /g, '_')}_${titleSuffix}.docx`;
    const isLandscape = titleSuffix === 'Learning_Plan';
    const orientation = isLandscape ? 'landscape' : 'portrait';

    const sourceHTML = `
      <html xmlns:o='urn:schemas-microsoft-com:office:office' xmlns:w='urn:schemas-microsoft-com:office:word' xmlns='http://www.w3.org/TR/REC-html40'>
      <head>
        <meta charset='utf-8'>
        <style>
          @page {
            size: A4 ${orientation};
            margin: 0.5in;
            mso-page-orientation: ${orientation};
          }
          body { font-family: 'Arial', sans-serif; font-size: 8.5pt; color: #000; }
          table { width: 100%; border-collapse: collapse; margin-bottom: 12pt; border: 1.5px solid black; }
          th, td { border: 1px solid black; padding: 4pt; vertical-align: top; }
          th { background-color: #f2f2f2; font-weight: bold; text-align: center; font-size: 8.5pt; text-transform: uppercase; }
          h1, h2, h3 { text-align: center; margin: 4pt 0; text-transform: uppercase; }
          h1 { font-size: 14pt; }
          h2 { font-size: 12pt; }
          .page-break { page-break-after: always; mso-special-character: page-break; }
          ul, ol { margin: 2px 0 2px 15px; padding: 0; }
          li { margin-bottom: 2px; }
          img { max-height: 80px; }
        </style>
      </head>
      <body>${html}</body>
      </html>`;

    const blob = new Blob([sourceHTML], { type: 'application/msword' });
    const link = document.createElement('a');
    link.href = URL.createObjectURL(blob);
    link.download = fileName;
    link.click();
  };

  return (
    <>
      <style>{STYLES}</style>
      <div className="app-container">
        <aside className="sidebar">
          <header className="sidebar-header">
            <h1>TVET EduPlanner</h1>
            <p>Smart CDACC Matrix Generator</p>
          </header>
          <form onSubmit={handleGenerateLP} className="input-form">
            <div className="form-group">
              <label>Unit of Competency</label>
              <input type="text" value={unitTitle} onChange={(e) => setUnitTitle(e.target.value)} required disabled={isLoading || isGeneratingSP} />
            </div>

            <div className="form-grid">
              <div className="form-group">
                <label>Level</label>
                <input type="text" value={level} onChange={(e) => setLevel(e.target.value)} required disabled={isLoading || isGeneratingSP} />
              </div>
              <div className="form-group">
                <label>Trainer Number</label>
                <input type="text" value={trainerNumber} onChange={(e) => setTrainerNumber(e.target.value)} disabled={isLoading || isGeneratingSP} />
              </div>
            </div>

            <div className="form-group">
              <label>Trainer Name</label>
              <input type="text" value={trainerName} onChange={(e) => setTrainerName(e.target.value)} required disabled={isLoading || isGeneratingSP} />
            </div>

            <div className="form-group">
              <label>Institution Name</label>
              <input type="text" value={institutionName} onChange={(e) => setInstitutionName(e.target.value)} required disabled={isLoading || isGeneratingSP} />
            </div>

            <div className="form-group">
              <label>Institution Logo</label>
              <div className="logo-uploader">
                <input type="file" id="logoUpload" accept="image/*" onChange={handleLogoUpload} style={{ display: 'none' }} />
                <label htmlFor="logoUpload" className="logo-upload-label">
                  {logoSrc ? <img src={logoSrc} className="logo-preview" /> : <span>🖼️ Upload</span>}
                </label>
                {logoSrc && <button type="button" className="remove-logo-btn" onClick={() => setLogoSrc('')} disabled={isLoading || isGeneratingSP}>Remove</button>}
              </div>
            </div>

            <div className="form-grid">
              <div className="form-group">
                <label>Weeks</label>
                <input type="number" value={numWeeks} onChange={(e) => setNumWeeks(e.target.value)} required min="1" disabled={isLoading || isGeneratingSP} />
              </div>
              <div className="form-group">
                <label>Sessions/Week</label>
                <input type="number" value={numLessons} onChange={(e) => setNumLessons(e.target.value)} required min="1" disabled={isLoading || isGeneratingSP} />
              </div>
            </div>

            <div className="form-group">
              <label>Class / Group</label>
              <input type="text" value={classGroup} onChange={(e) => setClassGroup(e.target.value)} disabled={isLoading || isGeneratingSP} />
            </div>

            <div className="form-group">
              <label>Curriculum Benchmarks (Include Unit Code)</label>
              <textarea 
                value={curriculum} 
                onChange={(e) => setCurriculum(e.target.value)} 
                rows={6} 
                required 
                placeholder="Paste the curriculum text, including the Unit Code..."
                disabled={isLoading || isGeneratingSP}
              ></textarea>
            </div>

            <button type="submit" className="generate-btn" disabled={isLoading || isGeneratingSP || !isApiConfigured}>
              {isLoading ? 'Processing Matrix...' : '1. Generate Learning Plan Preview'}
            </button>
            {!isApiConfigured && <p className="api-notice">⚠️ API Key Missing</p>}
          </form>

          {learningPlan && !isGeneratingSP && (
             <div className="next-step-promo">
                <p>Learning Plan Matrix ready with Logo! Review and generate all Session Plans.</p>
                <button onClick={handleGenerateSPs} className="generate-btn secondary">
                   2. Generate All Session Plans
                </button>
             </div>
          )}
        </aside>

        <main className="main-content">
          {(isLoading || isGeneratingSP) && (
            <div className="loading-spinner">
              <div className="spinner"></div>
              <h3>{generationStep}</h3>
              <p>Adding institutional logo and ensuring full data population...</p>
            </div>
          )}

          {error && <div className="error-message">{error}</div>}

          {!isLoading && !isGeneratingSP && !learningPlan && !error && (
             <div className="placeholder">
                <div className="placeholder-icon">📐</div>
                <h2>CDACC Matrix Planner</h2>
                <p><b>Step 1:</b> Generate the Learning Plan Matrix with Logo (A4 Landscape)<br/><b>Step 2:</b> Generate Session Plans (A4 Portrait)</p>
                <p className="hint">Upload your logo to include it in all generated documents!</p>
             </div>
          )}

          {(learningPlan || sessionPlans) && (
            <div className="results-container">
              <div className="tabs-bar">
                <div className="tabs">
                  <button className={`tab-btn ${activeTab === 'learningPlan' ? 'active' : ''}`} onClick={() => setActiveTab('learningPlan')}>
                    Learning Plan (Landscape)
                  </button>
                  <button className={`tab-btn ${activeTab === 'sessionPlans' ? 'active' : ''}`} onClick={() => setActiveTab('sessionPlans')} disabled={!sessionPlans && !isGeneratingSP}>
                    Session Plans (Portrait) {isGeneratingSP && '...'}
                  </button>
                </div>
                <div className="actions">
                  <button onClick={() => handleDownload(activeTab === 'learningPlan' ? learningPlan : sessionPlans, activeTab === 'learningPlan' ? 'Learning_Plan' : 'Session_Plans')} className="download-btn-top">
                    Download .docx
                  </button>
                </div>
              </div>

              <div className="tab-content">
                <div className={`a4-preview ${activeTab === 'learningPlan' ? 'landscape' : 'portrait'}`}>
                   <div className="html-output" dangerouslySetInnerHTML={{ __html: activeTab === 'learningPlan' ? learningPlan : sessionPlans }} />
                   {!sessionPlans && activeTab === 'sessionPlans' && isGeneratingSP && (
                      <div className="generating-inline-overlay">
                         <div className="spinner"></div>
                         <p>Populating session detail blocks...</p>
                      </div>
                   )}
                </div>
              </div>
            </div>
          )}
        </main>
      </div>
    </>
  );
};

const STYLES = `
  :root {
    --primary-color: #0f172a;
    --accent-color: #2563eb;
    --secondary-color: #10b981;
    --bg-color: #f1f5f9;
    --surface-color: #ffffff;
    --border-color: #cbd5e1;
    --text-main: #1e293b;
    --text-muted: #64748b;
  }
  * { box-sizing: border-box; margin: 0; padding: 0; }
  body { font-family: 'Inter', sans-serif; background: var(--bg-color); color: var(--text-main); line-height: 1.4; }
  .app-container { display: flex; height: 100vh; overflow: hidden; padding: 0.5rem; gap: 0.5rem; }

  .sidebar { width: 350px; background: var(--surface-color); border-radius: 8px; padding: 1rem; display: flex; flex-direction: column; border: 1px solid var(--border-color); overflow-y: auto; box-shadow: 0 1px 2px rgba(0,0,0,0.05); }
  .sidebar-header { margin-bottom: 1rem; border-bottom: 2px solid var(--accent-color); padding-bottom: 0.5rem; }
  .sidebar-header h1 { font-size: 1.1rem; color: var(--primary-color); font-weight: 800; }
  .sidebar-header p { font-size: 0.65rem; color: var(--accent-color); text-transform: uppercase; font-weight: 700; letter-spacing: 0.05em; }

  .form-group { margin-bottom: 0.65rem; }
  .form-group label { display: block; font-size: 0.65rem; font-weight: 700; margin-bottom: 0.2rem; color: var(--text-muted); text-transform: uppercase; }
  .form-group input, .form-group textarea { width: 100%; padding: 0.45rem; border: 1px solid var(--border-color); border-radius: 4px; font-size: 0.75rem; font-family: inherit; }
  .form-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 0.4rem; }

  .logo-uploader { display: flex; align-items: center; gap: 0.4rem; }
  .logo-upload-label { width: 36px; height: 36px; border: 1px dashed var(--border-color); border-radius: 4px; display: flex; align-items: center; justify-content: center; cursor: pointer; background: #fafafa; font-size: 0.5rem; }
  .logo-preview { width: 100%; height: 100%; object-fit: contain; }
  .remove-logo-btn { font-size: 0.6rem; color: #dc2626; border: none; background: none; cursor: pointer; text-decoration: underline; }

  .generate-btn { padding: 0.75rem; background: var(--accent-color); color: white; border: none; border-radius: 4px; font-weight: 700; cursor: pointer; margin-top: 0.5rem; transition: background 0.2s; font-size: 0.8rem; width: 100%; }
  .generate-btn:hover { background: #1d4ed8; }
  .generate-btn.secondary { background: var(--secondary-color); margin-top: 1rem; }
  .generate-btn.secondary:hover { background: #059669; }
  .generate-btn:disabled { background: #94a3b8; cursor: not-allowed; }

  .next-step-promo { margin-top: 1.5rem; padding: 1rem; background: #ecfdf5; border: 1px solid #10b981; border-radius: 6px; text-align: center; }
  .next-step-promo p { font-size: 0.75rem; font-weight: 600; color: #065f46; margin-bottom: 0.5rem; }

  .main-content { flex: 1; background: #64748b; border-radius: 8px; display: flex; flex-direction: column; overflow: hidden; position: relative; }
  .placeholder { flex: 1; display: flex; flex-direction: column; align-items: center; justify-content: center; color: #334155; text-align: center; padding: 2rem; background: #f1f5f9; border-radius: 4px; margin: 4px; }
  .placeholder-icon { font-size: 2.5rem; margin-bottom: 0.5rem; opacity: 0.1; }
  .hint { font-size: 0.75rem; font-weight: 600; color: var(--accent-color); margin-top: 1rem; }

  .loading-spinner { position: absolute; inset: 0; background: rgba(255,255,255,0.95); display: flex; flex-direction: column; align-items: center; justify-content: center; z-index: 50; }
  .spinner { width: 36px; height: 36px; border: 3px solid #e2e8f0; border-top: 3px solid var(--accent-color); border-radius: 50%; animation: spin 1s linear infinite; margin-bottom: 0.75rem; }
  @keyframes spin { 0% { transform: rotate(0deg); } 100% { transform: rotate(360deg); } }

  .results-container { flex: 1; display: flex; flex-direction: column; overflow: hidden; }
  .tabs-bar { display: flex; justify-content: space-between; align-items: center; padding: 0.4rem 0.75rem; background: #ffffff; border-bottom: 1px solid #cbd5e1; }
  .tabs { display: flex; gap: 0.4rem; }
  .tab-btn { padding: 0.4rem 0.6rem; border: none; background: #f1f5f9; font-weight: 700; color: #475569; cursor: pointer; border-radius: 4px; font-size: 0.7rem; }
  .tab-btn.active { color: white; background: var(--accent-color); }
  .download-btn-top { padding: 0.35rem 0.7rem; background: #0f172a; color: white; border: none; border-radius: 4px; font-size: 0.7rem; cursor: pointer; font-weight: 600; }

  .tab-content { flex: 1; overflow: auto; padding: 1.5rem; display: flex; flex-direction: column; align-items: center; position: relative; }
  .a4-preview { background: white; padding: 0.4in; box-shadow: 0 10px 30px -5px rgba(0, 0, 0, 0.4); border: 1.5px solid #000; box-sizing: content-box; position: relative; }
  .a4-preview.landscape { width: 11in; min-height: 8.5in; }
  .a4-preview.portrait { width: 8in; min-height: 11in; }

  .generating-inline-overlay { position: absolute; inset: 0; background: rgba(255,255,255,0.8); display: flex; flex-direction: column; align-items: center; justify-content: center; z-index: 5; }

  .html-output { color: black; font-family: 'Times New Roman', Times, serif; }
  .html-output table { border-collapse: collapse; width: 100%; margin-bottom: 8px; border: 1.5px solid black; }
  .html-output th, .html-output td { border: 1.5px solid black; padding: 3px; text-align: left; font-size: 7.5pt; vertical-align: top; line-height: 1.15; word-wrap: break-word; }
  .html-output th { background: #f8fafc; font-weight: bold; text-align: center; text-transform: uppercase; }
  .html-output h1 { font-size: 12pt; margin: 4px 0; text-align: center; }
  .html-output h2 { font-size: 10pt; margin: 2px 0; text-align: center; }
  .html-output p { font-size: 8pt; margin: 2px 0; }
  .html-output ul, .html-output ol { margin: 1px 0 1px 12px; padding: 0; }
  .html-output li { margin-bottom: 1px; }

  .error-message { background: #fee2e2; color: #b91c1c; padding: 0.75rem; border-radius: 4px; margin: 1rem; text-align: center; font-size: 0.75rem; font-weight: 600; border: 1px solid #f87171; }
  .api-notice { font-size: 0.6rem; color: #dc2626; margin-top: 0.25rem; font-weight: bold; text-align: center; }

  @media (max-width: 1100px) {
    .app-container { flex-direction: column; height: auto; overflow: visible; }
    .sidebar { width: 100%; height: auto; }
    .main-content { height: 800px; }
  }
`;

const container = document.getElementById('root');
const root = createRoot(container!);
root.render(<App />);

import React, { useState, useEffect } from 'react';
import { createRoot } from 'react-dom/client';
import { GoogleGenAI } from "@google/genai";

const App = () => {
  // --- STATE MANAGEMENT ---
  const [unitTitle, setUnitTitle] = useState('DRAINAGE SYSTEM INSTALLATION I');
  const [level, setLevel] = useState('Level 3');
  const [trainerName, setTrainerName] = useState('Faith Chess');
  const [trainerNumber, setTrainerNumber] = useState('');
  const [institutionName, setInstitutionName] = useState('ELDAMA RAVINE TVC');
  const [numWeeks, setNumWeeks] = useState('12');
  const [numLessons, setNumLessons] = useState('3');
  const [classGroup, setClassGroup] = useState('F-PLUM/24J');
  const [numTrainees, setNumTrainees] = useState('15');
  const [curriculum, setCurriculum] = useState(
    `Unit Code: CON/CU/PLM/CR/03/3/MB

Skill or Job Task:
Install environmentally responsive and resource-efficient domestic drainage system, involving installation and maintenance of above and below ground drainage systems.

Benchmark or Criterial to be used:
1. Install above ground drainage system
2. Install below ground drainage system
3. Interpret simple domestic drainage system drawings
4. Maintain drainage systems`
  );

  const [learningPlan, setLearningPlan] = useState('');
  const [sessionPlans, setSessionPlans] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [isGeneratingSP, setIsGeneratingSP] = useState(false);
  const [generationStep, setGenerationStep] = useState('');
  const [error, setError] = useState('');
  const [activeTab, setActiveTab] = useState('learningPlan');
  const [isApiConfigured, setIsApiConfigured] = useState(false);
  const [logoSrc, setLogoSrc] = useState('');

  // --- API KEY CHECK ---
  useEffect(() => {
    const keyIsAvailable = typeof process !== 'undefined' &&
                           typeof process.env !== 'undefined' &&
                           !!process.env.API_KEY &&
                           process.env.API_KEY.trim() !== '';
    setIsApiConfigured(keyIsAvailable);
  }, []);

  const handleLogoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (loadEvent) => {
        setLogoSrc(loadEvent.target?.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const getLogoHtml = () => {
    if (!logoSrc) return `<div style="text-align:center; padding: 10px; border: 1px dashed #ccc; margin-bottom: 10px; font-weight: bold; font-size: 10pt;">[INSTITUTION LOGO]</div>`;
    return `<div style="text-align: center; margin-bottom: 10px;"><img src="${logoSrc}" alt="Logo" style="max-height: 80px; width: auto; display: inline-block;" /></div>`;
  };

  // Prepend Header and Logo to HTML
  const wrapWithHeader = (content: string, isLandscape: boolean) => {
    const logo = getLogoHtml();
    const orientationClass = isLandscape ? 'landscape-header' : 'portrait-header';
    return `
      <div class="${orientationClass}">
        ${logo}
        <h2 style="text-align: center; margin: 0; font-size: 14pt;">${institutionName}</h2>
        <h1 style="text-align: center; margin: 5px 0; text-transform: uppercase; font-size: 16pt;">${isLandscape ? 'LEARNING PLAN TEMPLATE' : 'SESSION PLAN'}</h1>
        ${content}
      </div>
    `;
  };

  // Clean AI response from Markdown code blocks
  const cleanResponse = (text: string) => {
    return text.replace(/```html/g, '').replace(/```/g, '').trim();
  };

  // --- STEP 1: GENERATE LEARNING PLAN ---
  const handleGenerateLP = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!isApiConfigured) {
      setError("Configuration Error: The API_KEY is not available in the environment.");
      return;
    }

    setIsLoading(true);
    setError('');
    setLearningPlan('');
    setSessionPlans('');
    setActiveTab('learningPlan');

    const currentDate = new Date().toLocaleDateString('en-GB');
    const totalSessions = parseInt(numWeeks) * parseInt(numLessons);
    const totalHours = totalSessions * 2;

    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    try {
      setGenerationStep('Designing CDACC Matrix (Landscape)...');
      const lpSystemInstruction = `You are a TVET CDACC expert. Your goal is to generate a comprehensive Learning Plan HTML table for A4 LANDSCAPE orientation.

      DO NOT include markdown code blocks like \`\`\`html. Return ONLY the HTML content.

      CONTENT REQUIREMENTS (EVERY COLUMN MUST BE COMPLETELY FILLED):
      1. WEEK: Sequential week numbers.
      2. SESSION NO: Sequential session numbers (1 to ${totalSessions}).
      3. SESSION TITLE: Specific topics based on the curriculum benchmarks.
      4. LEARNING OUTCOMES: Must start with: "By the end of the session, trainees should be able to..."
      5. TRAINER ACTIVITIES: Minimum 4 detailed, numbered steps for the trainer.
      6. TRAINEE ACTIVITIES: Minimum 4 detailed, numbered steps for the trainee.
      7. Resources & Refs: Specific tools, equipment, and books.
      8. Learning Checks/ Assessments: MUST follow this sub-section format for every cell:
         Knowledge: Oral questioning on definitions.
         Skills: Participation in discussion.
         Attitudes: Observation of engagement.
      9. Reflections & Date: Placeholder text like "Achievement noted on ___/___/2024".

      METADATA SECTION:
      Generate a metadata table first with:
      - Unit of Competency: ${unitTitle}
      - Unit Code: [EXTRACT FROM CURRICULUM]
      - Name of Trainer: ${trainerName} (${trainerNumber})
      - Institution: ${institutionName} | Level: ${level}
      - Date of Prep: ${currentDate}
      - Number of Trainees: ${numTrainees} | Class: ${classGroup}
      - Total Hours: ${totalHours} | Total Sessions: ${totalSessions}

      Then provide the main 9-column Matrix Table. Use border="1" and width="100%".`;

      const lpResponse = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Curriculum: ${curriculum}. Generate the Learning Plan table for ${totalSessions} sessions. Ensure EVERY cell is robustly filled.`,
        config: { systemInstruction: lpSystemInstruction }
      });

      if (!lpResponse.text) throw new Error("The AI returned an empty response. Please try again.");

      const rawContent = cleanResponse(lpResponse.text);
      setLearningPlan(wrapWithHeader(rawContent, true));

    } catch (err: any) {
      console.error(err);
      setError(err.message || 'An error occurred during generation.');
    } finally {
      setIsLoading(false);
      setGenerationStep('');
    }
  };

  // --- STEP 2: GENERATE SESSION PLANS ---
  const handleGenerateSPs = async () => {
    if (!isApiConfigured || !learningPlan) return;

    setIsGeneratingSP(true);
    setError('');
    setActiveTab('sessionPlans');

    const totalSessions = parseInt(numWeeks) * parseInt(numLessons);
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    try {
      const batchSize = 2; 
      const numBatches = Math.ceil(totalSessions / batchSize);
      let fullSpContent = '';

      for (let i = 0; i < numBatches; i++) {
        const start = i * batchSize + 1;
        const end = Math.min((i + 1) * batchSize, totalSessions);
        setGenerationStep(`Building Detailed Session Plans ${start}-${end}...`);

        const spSystemInstruction = `You are a TVET CDACC expert. Generate highly detailed Session Plans in HTML for A4 PORTRAIT.

        DO NOT use markdown code blocks. Return ONLY the HTML.

        EVERY SECTION MUST BE FILLED.
        Each session plan must include:
        1. Metadata table (Unit Name, Code, Session Number, Date, Time).
        2. Delivery Table with specific segments:
           - Bridge-in (5 min): How the trainer starts.
           - Outcomes: "By the end of the session, trainees should be able to..."
           - Pre-assessment (10 min): Knowledge check.
           - Participatory Learning (80 min): Detailed Trainer vs Trainee steps (Min 6 steps each).
           - Post-Assessment (15 min): Specific check for understanding.
           - Closure (10 min): Summary and next steps.

        Separate each session with <div class="page-break"></div>.`;

        const spResponse = await ai.models.generateContent({
          model: 'gemini-3-flash-preview',
          contents: `Using this Learning Plan for context: ${learningPlan.substring(0, 3000)}, generate full Session Plans for Sessions ${start} to ${end}.`,
          config: { systemInstruction: spSystemInstruction }
        });

        fullSpContent += cleanResponse(spResponse.text || '');
      }
      setSessionPlans(wrapWithHeader(fullSpContent, false));
    } catch (err: any) {
      console.error(err);
      setError(err.message || 'An error occurred during Session Plan generation.');
    } finally {
      setIsGeneratingSP(false);
      setGenerationStep('');
    }
  };

  const handleDownload = (html: string, titleSuffix: string) => {
    if (!html) return;
    const fileName = `${unitTitle.replace(/ /g, '_')}_${titleSuffix}.docx`;
    const orientation = titleSuffix === 'Learning_Plan' ? 'landscape' : 'portrait';

    const sourceHTML = `
      <html xmlns:o='urn:schemas-microsoft-com:office:office' xmlns:w='urn:schemas-microsoft-com:office:word' xmlns='http://www.w3.org/TR/REC-html40'>
      <head>
        <meta charset='utf-8'>
        <style>
          @page { size: A4 ${orientation}; margin: 0.5in; mso-page-orientation: ${orientation}; }
          body { font-family: 'Arial', sans-serif; font-size: 8.5pt; color: #000; }
          table { width: 100%; border-collapse: collapse; margin-bottom: 10pt; border: 1px solid black; }
          th, td { border: 1px solid black; padding: 4pt; vertical-align: top; }
          th { background-color: #f2f2f2; font-weight: bold; text-align: center; text-transform: uppercase; }
          h1, h2, h3 { text-align: center; margin: 4pt 0; text-transform: uppercase; }
          h1 { font-size: 14pt; }
          h2 { font-size: 12pt; }
          .page-break { page-break-after: always; mso-special-character: page-break; }
          img { max-height: 80px; width: auto; }
        </style>
      </head>
      <body>${html}</body>
      </html>`;

    const blob = new Blob([sourceHTML], { type: 'application/msword' });
    const link = document.createElement('a');
    link.href = URL.createObjectURL(blob);
    link.download = fileName;
    link.click();
  };

  return (
    <>
      <style>{STYLES}</style>
      <div className="app-container">
        <aside className="sidebar">
          <header className="sidebar-header">
            <h1>TVET EduPlanner</h1>
            <p>Smart CDACC Matrix Generator</p>
          </header>
          <form onSubmit={handleGenerateLP} className="input-form">
            <div className="form-group">
              <label>Unit of Competency</label>
              <input type="text" value={unitTitle} onChange={(e) => setUnitTitle(e.target.value)} required disabled={isLoading || isGeneratingSP} />
            </div>

            <div className="form-grid">
              <div className="form-group">
                <label>Level</label>
                <input type="text" value={level} onChange={(e) => setLevel(e.target.value)} required disabled={isLoading || isGeneratingSP} />
              </div>
              <div className="form-group">
                <label>Trainer ID/No.</label>
                <input type="text" value={trainerNumber} onChange={(e) => setTrainerNumber(e.target.value)} disabled={isLoading || isGeneratingSP} />
              </div>
            </div>

            <div className="form-group">
              <label>Trainer Name</label>
              <input type="text" value={trainerName} onChange={(e) => setTrainerName(e.target.value)} required disabled={isLoading || isGeneratingSP} />
            </div>

            <div className="form-group">
              <label>Institution Name</label>
              <input type="text" value={institutionName} onChange={(e) => setInstitutionName(e.target.value)} required disabled={isLoading || isGeneratingSP} />
            </div>

            <div className="form-group">
              <label>Institution Logo</label>
              <div className="logo-uploader">
                <input type="file" id="logoUpload" accept="image/*" onChange={handleLogoUpload} style={{ display: 'none' }} />
                <label htmlFor="logoUpload" className="logo-upload-label">
                  {logoSrc ? <img src={logoSrc} className="logo-preview" /> : <span>🖼️ Upload</span>}
                </label>
                {logoSrc && <button type="button" className="remove-logo-btn" onClick={() => setLogoSrc('')} disabled={isLoading || isGeneratingSP}>Remove</button>}
              </div>
            </div>

            <div className="form-grid">
              <div className="form-group">
                <label>Total Weeks</label>
                <input type="number" value={numWeeks} onChange={(e) => setNumWeeks(e.target.value)} required min="1" disabled={isLoading || isGeneratingSP} />
              </div>
              <div className="form-group">
                <label>Sessions/Week</label>
                <input type="number" value={numLessons} onChange={(e) => setNumLessons(e.target.value)} required min="1" disabled={isLoading || isGeneratingSP} />
              </div>
            </div>

            <div className="form-group">
              <label>Class / Group</label>
              <input type="text" value={classGroup} onChange={(e) => setClassGroup(e.target.value)} disabled={isLoading || isGeneratingSP} />
            </div>

            <div className="form-group">
              <label>Benchmarks & Benchmarks Content</label>
              <textarea 
                value={curriculum} 
                onChange={(e) => setCurriculum(e.target.value)} 
                rows={5} 
                required 
                placeholder="Include Unit Code for extraction..."
                disabled={isLoading || isGeneratingSP}
              ></textarea>
            </div>

            <button type="submit" className="generate-btn" disabled={isLoading || isGeneratingSP || !isApiConfigured}>
              {isLoading ? 'Wait, generating content...' : '1. Generate Learning Plan Matrix'}
            </button>
            {!isApiConfigured && <p className="api-notice">⚠️ API Key Missing</p>}
          </form>

          {learningPlan && !isGeneratingSP && (
             <div className="next-step-promo">
                <p>Learning Plan Matrix ready! Now build the session-by-session plans.</p>
                <button onClick={handleGenerateSPs} className="generate-btn secondary">
                   2. Build Session Plans (Portrait)
                </button>
             </div>
          )}
        </aside>

        <main className="main-content">
          {(isLoading || isGeneratingSP) && (
            <div className="loading-spinner">
              <div className="spinner"></div>
              <h3>{generationStep}</h3>
              <p>Ensuring every column is completely filled with high-detail CDACC content.</p>
            </div>
          )}

          {error && <div className="error-message">{error}</div>}

          {!isLoading && !isGeneratingSP && !learningPlan && !error && (
             <div className="placeholder">
                <div className="placeholder-icon">📐</div>
                <h2>Institutional Matrix Generator</h2>
                <p>Fill in the form to generate standard TVET CDACC documentation.</p>
                <p className="hint">The logo will appear at the top of your generated documents.</p>
             </div>
          )}

          {(learningPlan || sessionPlans) && (
            <div className="results-container">
              <div className="tabs-bar">
                <div className="tabs">
                  <button className={`tab-btn ${activeTab === 'learningPlan' ? 'active' : ''}`} onClick={() => setActiveTab('learningPlan')}>
                    Matrix View (Landscape)
                  </button>
                  <button className={`tab-btn ${activeTab === 'sessionPlans' ? 'active' : ''}`} onClick={() => setActiveTab('sessionPlans')} disabled={!sessionPlans && !isGeneratingSP}>
                    Session Plans (Portrait)
                  </button>
                </div>
                <div className="actions">
                  <button onClick={() => handleDownload(activeTab === 'learningPlan' ? learningPlan : sessionPlans, activeTab === 'learningPlan' ? 'Learning_Plan' : 'Session_Plans')} className="download-btn-top">
                    Download .docx
                  </button>
                </div>
              </div>

              <div className="tab-content">
                <div className={`a4-preview ${activeTab === 'learningPlan' ? 'landscape' : 'portrait'}`}>
                   <div className="html-output" dangerouslySetInnerHTML={{ __html: activeTab === 'learningPlan' ? learningPlan : sessionPlans }} />
                   {!sessionPlans && activeTab === 'sessionPlans' && isGeneratingSP && (
                      <div className="generating-inline-overlay">
                         <div className="spinner"></div>
                         <p>Constructing portrait session plan blocks...</p>
                      </div>
                   )}
                </div>
              </div>
            </div>
          )}
        </main>
      </div>
    </>
  );
};

const STYLES = `
  :root {
    --primary-color: #0f172a;
    --accent-color: #2563eb;
    --secondary-color: #10b981;
    --bg-color: #f1f5f9;
    --surface-color: #ffffff;
    --border-color: #cbd5e1;
    --text-main: #1e293b;
    --text-muted: #64748b;
  }
  * { box-sizing: border-box; margin: 0; padding: 0; }
  body { font-family: 'Inter', sans-serif; background: var(--bg-color); color: var(--text-main); line-height: 1.4; }
  .app-container { display: flex; height: 100vh; overflow: hidden; padding: 0.5rem; gap: 0.5rem; }

  .sidebar { width: 350px; background: var(--surface-color); border-radius: 8px; padding: 1rem; display: flex; flex-direction: column; border: 1px solid var(--border-color); overflow-y: auto; box-shadow: 0 1px 2px rgba(0,0,0,0.05); }
  .sidebar-header { margin-bottom: 1rem; border-bottom: 2px solid var(--accent-color); padding-bottom: 0.5rem; }
  .sidebar-header h1 { font-size: 1.1rem; color: var(--primary-color); font-weight: 800; }
  .sidebar-header p { font-size: 0.65rem; color: var(--accent-color); text-transform: uppercase; font-weight: 700; letter-spacing: 0.05em; }

  .form-group { margin-bottom: 0.65rem; }
  .form-group label { display: block; font-size: 0.65rem; font-weight: 700; margin-bottom: 0.2rem; color: var(--text-muted); text-transform: uppercase; }
  .form-group input, .form-group textarea { width: 100%; padding: 0.45rem; border: 1px solid var(--border-color); border-radius: 4px; font-size: 0.75rem; font-family: inherit; }
  .form-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 0.4rem; }

  .logo-uploader { display: flex; align-items: center; gap: 0.4rem; }
  .logo-upload-label { width: 40px; height: 40px; border: 1px dashed var(--border-color); border-radius: 4px; display: flex; align-items: center; justify-content: center; cursor: pointer; background: #fafafa; font-size: 0.5rem; overflow: hidden; }
  .logo-preview { width: 100%; height: 100%; object-fit: contain; }
  .remove-logo-btn { font-size: 0.6rem; color: #dc2626; border: none; background: none; cursor: pointer; text-decoration: underline; }

  .generate-btn { padding: 0.75rem; background: var(--accent-color); color: white; border: none; border-radius: 4px; font-weight: 700; cursor: pointer; margin-top: 0.5rem; transition: background 0.2s; font-size: 0.8rem; width: 100%; }
  .generate-btn:hover { background: #1d4ed8; }
  .generate-btn.secondary { background: var(--secondary-color); margin-top: 1rem; }
  .generate-btn:disabled { background: #94a3b8; cursor: not-allowed; }

  .next-step-promo { margin-top: 1.5rem; padding: 1rem; background: #ecfdf5; border: 1px solid #10b981; border-radius: 6px; text-align: center; }
  .next-step-promo p { font-size: 0.75rem; font-weight: 600; color: #065f46; margin-bottom: 0.5rem; }

  .main-content { flex: 1; background: #64748b; border-radius: 8px; display: flex; flex-direction: column; overflow: hidden; position: relative; }
  .placeholder { flex: 1; display: flex; flex-direction: column; align-items: center; justify-content: center; color: #334155; text-align: center; padding: 2rem; background: #f1f5f9; border-radius: 4px; margin: 4px; }
  .placeholder-icon { font-size: 3rem; margin-bottom: 1rem; opacity: 0.1; }
  .hint { font-size: 0.75rem; font-weight: 600; color: var(--accent-color); margin-top: 1rem; }

  .loading-spinner { position: absolute; inset: 0; background: rgba(255,255,255,0.95); display: flex; flex-direction: column; align-items: center; justify-content: center; z-index: 50; }
  .spinner { width: 40px; height: 40px; border: 4px solid #e2e8f0; border-top: 4px solid var(--accent-color); border-radius: 50%; animation: spin 1s linear infinite; margin-bottom: 1rem; }
  @keyframes spin { 0% { transform: rotate(0deg); } 100% { transform: rotate(360deg); } }

  .results-container { flex: 1; display: flex; flex-direction: column; overflow: hidden; }
  .tabs-bar { display: flex; justify-content: space-between; align-items: center; padding: 0.5rem 1rem; background: #ffffff; border-bottom: 1px solid #cbd5e1; }
  .tabs { display: flex; gap: 0.5rem; }
  .tab-btn { padding: 0.5rem 0.75rem; border: none; background: #f1f5f9; font-weight: 700; color: #475569; cursor: pointer; border-radius: 4px; font-size: 0.75rem; }
  .tab-btn.active { color: white; background: var(--accent-color); }
  .download-btn-top { padding: 0.4rem 0.8rem; background: #0f172a; color: white; border: none; border-radius: 4px; font-size: 0.75rem; cursor: pointer; font-weight: 600; }

  .tab-content { flex: 1; overflow: auto; padding: 2rem; display: flex; flex-direction: column; align-items: center; background: #475569; }
  .a4-preview { background: white; padding: 0.5in; box-shadow: 0 20px 50px rgba(0, 0, 0, 0.5); border: 1px solid #000; box-sizing: border-box; }
  .a4-preview.landscape { width: 11.69in; min-height: 8.27in; }
  .a4-preview.portrait { width: 8.27in; min-height: 11.69in; }

  .generating-inline-overlay { position: absolute; inset: 0; background: rgba(255,255,255,0.7); display: flex; flex-direction: column; align-items: center; justify-content: center; z-index: 5; }

  .html-output { color: black; font-family: 'Times New Roman', serif; }
  .html-output table { border-collapse: collapse; width: 100%; margin-bottom: 10px; border: 1.5px solid black; }
  .html-output th, .html-output td { border: 1.5px solid black; padding: 4px; text-align: left; font-size: 8pt; vertical-align: top; }
  .html-output th { background: #f2f2f2; text-align: center; font-weight: bold; }
  .html-output img { max-height: 80px; width: auto; }
  .html-output .page-break { page-break-after: always; border-top: 2px dashed #ccc; margin: 40px 0; }

  .error-message { background: #fee2e2; color: #b91c1c; padding: 1rem; border-radius: 6px; margin: 1rem; text-align: center; font-size: 0.8rem; font-weight: 600; border: 1px solid #f87171; }
  .api-notice { font-size: 0.65rem; color: #dc2626; margin-top: 0.3rem; font-weight: bold; text-align: center; }

  @media (max-width: 1200px) {
    .app-container { flex-direction: column; height: auto; }
    .sidebar { width: 100%; height: auto; }
    .main-content { height: 700px; }
    .tab-content { padding: 1rem; }
    .a4-preview { transform: scale(0.8); transform-origin: top center; }
  }
`;

const container = document.getElementById('root');
const root = createRoot(container!);
root.render(<App />);

import React, { useState, useEffect } from 'react';
import { createRoot } from 'react-dom/client';
import { GoogleGenAI } from "@google/genai";

const App = () => {
  // --- STATE MANAGEMENT ---
  const [unitTitle, setUnitTitle] = useState('DRAINAGE SYSTEM INSTALLATION I');
  const [level, setLevel] = useState('Level 3');
  const [trainerName, setTrainerName] = useState('Faith Chess');
  const [trainerNumber, setTrainerNumber] = useState('');
  const [institutionName, setInstitutionName] = useState('ELDAMA RAVINE TVC');
  const [numWeeks, setNumWeeks] = useState('12');
  const [numLessons, setNumLessons] = useState('3');
  const [classGroup, setClassGroup] = useState('F-PLUM/24J');
  const [numTrainees, setNumTrainees] = useState('15');
  const [curriculum, setCurriculum] = useState(
    `Unit Code: CON/CU/PLM/CR/03/3/MB

Skill or Job Task:
Install environmentally responsive and resource-efficient domestic drainage system, involving installation and maintenance of above and below ground drainage systems.

Benchmark or Criterial to be used:
1. Install above ground drainage system
2. Install below ground drainage system
3. Interpret simple domestic drainage system drawings
4. Maintain drainage systems`
  );

  const [learningPlan, setLearningPlan] = useState('');
  const [sessionPlans, setSessionPlans] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [isGeneratingSP, setIsGeneratingSP] = useState(false);
  const [generationStep, setGenerationStep] = useState('');
  const [error, setError] = useState('');
  const [activeTab, setActiveTab] = useState('learningPlan');
  const [isApiConfigured, setIsApiConfigured] = useState(false);
  const [logoSrc, setLogoSrc] = useState('');

  // --- API KEY CHECK ---
  useEffect(() => {
    const keyIsAvailable = typeof process !== 'undefined' &&
                           typeof process.env !== 'undefined' &&
                           !!process.env.API_KEY &&
                           process.env.API_KEY.trim() !== '';
    setIsApiConfigured(keyIsAvailable);
  }, []);

  const handleLogoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (loadEvent) => {
        setLogoSrc(loadEvent.target?.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const getLogoHtml = () => {
    if (!logoSrc) return `<div style="text-align:center; padding: 10px; border: 1px dashed #ccc; margin-bottom: 10px; font-weight: bold; font-size: 10pt;">[INSTITUTION LOGO]</div>`;
    return `<div style="text-align: center; margin-bottom: 10px;"><img src="${logoSrc}" alt="Logo" style="max-height: 80px; width: auto; display: inline-block;" /></div>`;
  };

  // Prepend Header and Logo to HTML
  const wrapWithHeader = (content: string, title: string) => {
    const logo = getLogoHtml();
    return `
      <div class="document-wrapper">
        ${logo}
        <h2 style="text-align: center; margin: 0; font-size: 14pt;">${institutionName}</h2>
        <h1 style="text-align: center; margin: 5px 0; text-transform: uppercase; font-size: 16pt;">${title}</h1>
        ${content}
      </div>
    `;
  };

  // Clean AI response from Markdown code blocks
  const cleanResponse = (text: string) => {
    return text.replace(/```html/g, '').replace(/```/g, '').trim();
  };

  // --- STEP 1: GENERATE LEARNING PLAN (BATCHED) ---
  const handleGenerateLP = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!isApiConfigured) {
      setError("Configuration Error: The API_KEY is not available in the environment.");
      return;
    }

    setIsLoading(true);
    setError('');
    setLearningPlan('');
    setSessionPlans('');
    setActiveTab('learningPlan');

    const currentDate = new Date().toLocaleDateString('en-GB');
    const totalSessions = parseInt(numWeeks) * parseInt(numLessons);
    const totalHours = totalSessions * 2;
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    try {
      // PART A: Generate Metadata and Table Structure
      setGenerationStep('Preparing Matrix Structure...');
      const metaInstruction = `You are a TVET CDACC expert. Generate the Metadata section and Table Header for a Learning Plan.
      DO NOT use markdown blocks. Return ONLY HTML.

      Structure:
      1. A Metadata Table with:
         - Unit of Competency: ${unitTitle}
         - Unit Code: [EXTRACT FROM CURRICULUM]
         - Trainer: ${trainerName} (${trainerNumber})
         - Institution: ${institutionName} | Level: ${level}
         - Date: ${currentDate}
         - Number of Trainees: ${numTrainees} | Class: ${classGroup}
         - Total Unit Hours: ${totalHours} | Total Sessions: ${totalSessions}
      2. The opening <table> tag and <thead> with headers: WEEK, SESSION NO, SESSION TITLE, LEARNING OUTCOMES, TRAINER ACTIVITIES, TRAINEE ACTIVITIES, Resources & Refs, Learning Checks/ Assessments, Reflections & Date.

      DO NOT CLOSE the <table> tag.`;

      const metaResponse = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Curriculum: ${curriculum}. Generate the Learning Plan header and metadata table.`,
        config: { systemInstruction: metaInstruction }
      });

      let finalHtml = cleanResponse(metaResponse.text || '') + '<tbody>';

      // PART B: Generate Rows in Batches of 6 sessions
      const rowBatchSize = 6;
      const numRowBatches = Math.ceil(totalSessions / rowBatchSize);

      for (let i = 0; i < numRowBatches; i++) {
        const start = i * rowBatchSize + 1;
        const end = Math.min((i + 1) * rowBatchSize, totalSessions);
        setGenerationStep(`Populating Sessions ${start} to ${end} of ${totalSessions}...`);

        const rowInstruction = `You are a TVET CDACC expert. Generate exactly ${end - start + 1} rows for the Learning Plan table starting from session ${start}.
        DO NOT include <table> or <thead>. Return ONLY <tr> elements.

        STRICT COLUMN RULES (EVERY CELL MUST BE FULLY FILLED):
        1. LEARNING OUTCOMES: Must start with: "By the end of the session, trainees should be able to..."
        2. TRAINER ACTIVITIES: Min 4 detailed, numbered bullet points.
        3. TRAINEE ACTIVITIES: Min 4 detailed, numbered bullet points.
        4. Resources: List specific tools/refs.
        5. Learning Checks: MUST use Knowledge/Skills/Attitudes sub-sections for every cell.
           Example:
           Knowledge: Oral questioning on definitions.
           Skills: Participation in discussion.
           Attitudes: Observation of engagement.
        6. Reflections: Placeholder "Verified on ___/___/2024".`;

        const rowResponse = await ai.models.generateContent({
          model: 'gemini-3-flash-preview',
          contents: `Curriculum: ${curriculum}. Generate table rows for sessions ${start} to ${end}. Ensure every cell is filled.`,
          config: { systemInstruction: rowInstruction }
        });

        finalHtml += cleanResponse(rowResponse.text || '');
      }

      finalHtml += '</tbody></table>';
      setLearningPlan(wrapWithHeader(finalHtml, 'LEARNING PLAN TEMPLATE'));

    } catch (err: any) {
      console.error(err);
      setError(err.message || 'An error occurred during generation.');
    } finally {
      setIsLoading(false);
      setGenerationStep('');
    }
  };

  // --- STEP 2: GENERATE SESSION PLANS ---
  const handleGenerateSPs = async () => {
    if (!isApiConfigured || !learningPlan) return;

    setIsGeneratingSP(true);
    setError('');
    setActiveTab('sessionPlans');

    const totalSessions = parseInt(numWeeks) * parseInt(numLessons);
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    try {
      const batchSize = 2; 
      const numBatches = Math.ceil(totalSessions / batchSize);
      let fullSpContent = '';

      for (let i = 0; i < numBatches; i++) {
        const start = i * batchSize + 1;
        const end = Math.min((i + 1) * batchSize, totalSessions);
        setGenerationStep(`Building Detailed Session Plans ${start}-${end}...`);

        const spSystemInstruction = `You are a TVET CDACC expert. Generate highly detailed Session Plans in HTML for A4 PORTRAIT.
        DO NOT use markdown code blocks. Return ONLY the HTML.

        EVERY SECTION MUST BE FILLED. No blanks.
        Each plan:
        1. Metadata table (Unit Name, Code, Session Number, Date, Time).
        2. Delivery Table segments:
           - Bridge-in (5 min).
           - Outcomes: Must start with "By the end of the session, trainees should be able to...".
           - Pre-assessment (10 min).
           - Participatory Learning (80 min): Min 6 Trainer vs Trainee steps each.
           - Post-Assessment (15 min).
           - Closure (10 min).

        Separate sessions with <div class="page-break"></div>.`;

        const spResponse = await ai.models.generateContent({
          model: 'gemini-3-flash-preview',
          contents: `Using this Learning Plan for context: ${learningPlan.substring(0, 4000)}, generate full Session Plans for Sessions ${start} to ${end}.`,
          config: { systemInstruction: spSystemInstruction }
        });

        fullSpContent += cleanResponse(spResponse.text || '');
      }
      setSessionPlans(wrapWithHeader(fullSpContent, 'SESSION PLAN'));
    } catch (err: any) {
      console.error(err);
      setError(err.message || 'An error occurred during Session Plan generation.');
    } finally {
      setIsGeneratingSP(false);
      setGenerationStep('');
    }
  };

  const handleDownload = (html: string, titleSuffix: string) => {
    if (!html) return;
    const fileName = `${unitTitle.replace(/ /g, '_')}_${titleSuffix}.docx`;
    const orientation = titleSuffix === 'Learning_Plan' ? 'landscape' : 'portrait';

    const sourceHTML = `
      <html xmlns:o='urn:schemas-microsoft-com:office:office' xmlns:w='urn:schemas-microsoft-com:office:word' xmlns='http://www.w3.org/TR/REC-html40'>
      <head>
        <meta charset='utf-8'>
        <style>
          @page { size: A4 ${orientation}; margin: 0.5in; mso-page-orientation: ${orientation}; }
          body { font-family: 'Arial', sans-serif; font-size: 8.5pt; color: #000; }
          table { width: 100%; border-collapse: collapse; margin-bottom: 10pt; border: 1.5px solid black; }
          th, td { border: 1.5px solid black; padding: 4pt; vertical-align: top; }
          th { background-color: #f2f2f2; font-weight: bold; text-align: center; text-transform: uppercase; }
          h1, h2, h3 { text-align: center; margin: 4pt 0; text-transform: uppercase; }
          h1 { font-size: 14pt; }
          h2 { font-size: 12pt; }
          .page-break { page-break-after: always; mso-special-character: page-break; }
          img { max-height: 80px; width: auto; }
        </style>
      </head>
      <body>${html}</body>
      </html>`;

    const blob = new Blob([sourceHTML], { type: 'application/msword' });
    const link = document.createElement('a');
    link.href = URL.createObjectURL(blob);
    link.download = fileName;
    link.click();
  };

  return (
    <>
      <style>{STYLES}</style>
      <div className="app-container">
        <aside className="sidebar">
          <header className="sidebar-header">
            <h1>TVET EduPlanner</h1>
            <p>Institutional Document Generator</p>
          </header>
          <form onSubmit={handleGenerateLP} className="input-form">
            <div className="form-group">
              <label>Unit of Competency</label>
              <input type="text" value={unitTitle} onChange={(e) => setUnitTitle(e.target.value)} required disabled={isLoading || isGeneratingSP} />
            </div>

            <div className="form-grid">
              <div className="form-group">
                <label>Level</label>
                <input type="text" value={level} onChange={(e) => setLevel(e.target.value)} required disabled={isLoading || isGeneratingSP} />
              </div>
              <div className="form-group">
                <label>Trainer ID/No.</label>
                <input type="text" value={trainerNumber} onChange={(e) => setTrainerNumber(e.target.value)} disabled={isLoading || isGeneratingSP} />
              </div>
            </div>

            <div className="form-group">
              <label>Trainer Name</label>
              <input type="text" value={trainerName} onChange={(e) => setTrainerName(e.target.value)} required disabled={isLoading || isGeneratingSP} />
            </div>

            <div className="form-group">
              <label>Institution Name</label>
              <input type="text" value={institutionName} onChange={(e) => setInstitutionName(e.target.value)} required disabled={isLoading || isGeneratingSP} />
            </div>

            <div className="form-group">
              <label>Institution Logo</label>
              <div className="logo-uploader">
                <input type="file" id="logoUpload" accept="image/*" onChange={handleLogoUpload} style={{ display: 'none' }} />
                <label htmlFor="logoUpload" className="logo-upload-label">
                  {logoSrc ? <img src={logoSrc} className="logo-preview" /> : <span>🖼️ Upload</span>}
                </label>
                {logoSrc && <button type="button" className="remove-logo-btn" onClick={() => setLogoSrc('')} disabled={isLoading || isGeneratingSP}>Remove</button>}
              </div>
            </div>

            <div className="form-grid">
              <div className="form-group">
                <label>Total Weeks</label>
                <input type="number" value={numWeeks} onChange={(e) => setNumWeeks(e.target.value)} required min="1" disabled={isLoading || isGeneratingSP} />
              </div>
              <div className="form-group">
                <label>Sessions/Week</label>
                <input type="number" value={numLessons} onChange={(e) => setNumLessons(e.target.value)} required min="1" disabled={isLoading || isGeneratingSP} />
              </div>
            </div>

            <div className="form-group">
              <label>Benchmarks & Curriculum Text</label>
              <textarea 
                value={curriculum} 
                onChange={(e) => setCurriculum(e.target.value)} 
                rows={5} 
                required 
                placeholder="Include Unit Code for extraction..."
                disabled={isLoading || isGeneratingSP}
              ></textarea>
            </div>

            <button type="submit" className="generate-btn" disabled={isLoading || isGeneratingSP || !isApiConfigured}>
              {isLoading ? 'Wait, generating content...' : '1. Generate Learning Plan Matrix'}
            </button>
            {!isApiConfigured && <p className="api-notice">⚠️ API Key Missing</p>}
          </form>

          {learningPlan && !isGeneratingSP && (
             <div className="next-step-promo">
                <p>Matrix Complete! Now generate the portrait session plans.</p>
                <button onClick={handleGenerateSPs} className="generate-btn secondary">
                   2. Build Detailed Session Plans
                </button>
             </div>
          )}
        </aside>

        <main className="main-content">
          {(isLoading || isGeneratingSP) && (
            <div className="loading-spinner">
              <div className="spinner"></div>
              <h3>{generationStep}</h3>
              <p>Ensuring every session is fully documented with specific CDACC activities.</p>
            </div>
          )}

          {error && <div className="error-message">{error}</div>}

          {!isLoading && !isGeneratingSP && !learningPlan && !error && (
             <div className="placeholder">
                <div className="placeholder-icon">📐</div>
                <h2>Document Generator</h2>
                <p>Upload a logo and provide curriculum text to begin.</p>
                <p className="hint">The generator uses multi-batch processing to ensure no session is skipped.</p>
             </div>
          )}

          {(learningPlan || sessionPlans) && (
            <div className="results-container">
              <div className="tabs-bar">
                <div className="tabs">
                  <button className={`tab-btn ${activeTab === 'learningPlan' ? 'active' : ''}`} onClick={() => setActiveTab('learningPlan')}>
                    Matrix (Landscape)
                  </button>
                  <button className={`tab-btn ${activeTab === 'sessionPlans' ? 'active' : ''}`} onClick={() => setActiveTab('sessionPlans')} disabled={!sessionPlans && !isGeneratingSP}>
                    Session Plans (Portrait)
                  </button>
                </div>
                <div className="actions">
                  <button onClick={() => handleDownload(activeTab === 'learningPlan' ? learningPlan : sessionPlans, activeTab === 'learningPlan' ? 'Learning_Plan' : 'Session_Plans')} className="download-btn-top">
                    Download .docx
                  </button>
                </div>
              </div>

              <div className="tab-content">
                <div className={`a4-preview ${activeTab === 'learningPlan' ? 'landscape' : 'portrait'}`}>
                   <div className="html-output" dangerouslySetInnerHTML={{ __html: activeTab === 'learningPlan' ? learningPlan : sessionPlans }} />
                   {!sessionPlans && activeTab === 'sessionPlans' && isGeneratingSP && (
                      <div className="generating-inline-overlay">
                         <div className="spinner"></div>
                         <p>Constructing portrait session plan blocks...</p>
                      </div>
                   )}
                </div>
              </div>
            </div>
          )}
        </main>
      </div>
    </>
  );
};

const STYLES = `
  :root {
    --primary-color: #0f172a;
    --accent-color: #2563eb;
    --secondary-color: #10b981;
    --bg-color: #f1f5f9;
